import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';


export default class FourthDownModule extends BaseAlertModule {
  alertType = 'NFL_FOURTH_DOWN';
  sport = 'NFL';

  isTriggered(gameState: GameState): boolean {
    // Fourth down situations - game must be live and down must be 4
    return gameState.status === 'live' && 
           gameState.down === 4 &&
           (gameState.yardsToGo as number | undefined) !== undefined &&
           (gameState.fieldPosition as number | undefined) !== undefined;
  }

  generateAlert(gameState: GameState): AlertResult | null {
    // isTriggered() already called by engine - removed duplicate check
    const priority = (gameState.yardsToGo as number) <= 3 ? 95 : 85; // Higher priority for short yardage
    const fieldPosition = (gameState.fieldPosition as number) || 50;
    const yardsToGo = (gameState.yardsToGo as number) || 10;
    const dynamicMessage = this.createDynamicMessage(gameState);

    return {
      alertKey: `${gameState.gameId}_fourth_down_Q${gameState.quarter}_${yardsToGo}_${fieldPosition}`,
      type: this.alertType,
      message: `${gameState.awayTeam} @ ${gameState.homeTeam} | ${dynamicMessage}`,
      displayMessage: `🏈 ${dynamicMessage} | Q${gameState.quarter}`,

      context: {
        gameId: gameState.gameId,
        homeTeam: gameState.homeTeam,
        awayTeam: gameState.awayTeam,
        homeScore: gameState.homeScore,
        awayScore: gameState.awayScore,
        down: gameState.down,
        yardsToGo: gameState.yardsToGo,
        fieldPosition: gameState.fieldPosition,
        quarter: gameState.quarter,
        timeRemaining: gameState.timeRemaining,
        isFourthDown: true,
        // NFL-specific context for AI enhancement
        nflContext: {
          isFourthDown: true,
          isShortYardage: yardsToGo <= 3,
          isInRedZone: fieldPosition <= 20,
          isGoalLine: fieldPosition <= 5,
          scoreDifferential: Math.abs(gameState.homeScore - gameState.awayScore),
          timePressure: this.getTimePressureLevel(gameState),
          conversionProbability: this.getConversionProbability(gameState),
          decisionRecommendation: this.getDecisionRecommendation(gameState)
        }
      },
      priority
    };
  }

  calculateProbability(gameState: GameState): number {
    if (!this.isTriggered(gameState)) return 0;

    let probability = 90; // Base high probability for fourth down

    // Higher probability for shorter yardage
    if ((gameState.yardsToGo as number) <= 1) probability = 100;
    else if ((gameState.yardsToGo as number) <= 3) probability = 95;
    else if ((gameState.yardsToGo as number) <= 5) probability = 90;

    // Higher probability in red zone
    if ((gameState.fieldPosition as number) <= 20) probability += 5;

    // Higher probability in fourth quarter
    if (gameState.quarter === 4) probability += 5;

    return Math.min(probability, 100);
  }

  private getTimePressureLevel(gameState: GameState): string {
    if (!gameState.quarter || !gameState.timeRemaining) return 'NORMAL';

    const timeSeconds = this.parseTimeToSeconds(gameState.timeRemaining as string);

    if (gameState.quarter === 4) {
      if (timeSeconds <= 60) return 'CRITICAL';   // Final minute
      if (timeSeconds <= 120) return 'HIGH';      // Two-minute warning
      if (timeSeconds <= 300) return 'MEDIUM';    // Last 5 minutes
    }

    if (gameState.quarter === 2 && timeSeconds <= 120) {
      return 'MEDIUM';  // End of half
    }

    return 'NORMAL';
  }

  private getConversionProbability(gameState: GameState): number {
    if (!gameState.yardsToGo || !gameState.fieldPosition) return 50;

    let probability = 50; // Base conversion rate

    const yardsToGo = gameState.yardsToGo as number;
    const fieldPosition = gameState.fieldPosition as number;

    // Distance factors
    if (yardsToGo <= 1) probability = 85;
    else if (yardsToGo <= 3) probability = 70;
    else if (yardsToGo <= 5) probability = 55;
    else probability = 35;

    // Field position adjustments
    if (fieldPosition <= 10) probability += 10; // Goal line boost
    else if (fieldPosition <= 30) probability += 5; // Red zone boost

    // Weather impact adjustments (for outdoor stadiums only)
    if (gameState.weather && (gameState.weather as any).isOutdoorStadium) {
      const weatherImpact = (gameState.weather as any).impact;

      // Weather affects conversion strategies differently based on distance
      if (yardsToGo <= 3) {
        // Short yardage - weather favors running
        if (weatherImpact.preferredStrategy === 'run-heavy') {
          probability += 8; // Weather favors short yardage running
        } else if (weatherImpact.passingConditions === 'dangerous') {
          probability += 5; // Must run in bad passing weather
        }
      } else {
        // Longer conversions - weather affects passing
        if (weatherImpact.passingConditions === 'dangerous') {
          probability -= 12; // Hard to convert long yardage in bad weather
        } else if (weatherImpact.passingConditions === 'poor') {
          probability -= 6; // Moderate passing difficulty
        }
      }

      // Extreme weather generally favors conservative decisions
      if (weatherImpact.weatherAlert) {
        probability -= 5; // Slightly lower conversion due to conditions
      }
    }

    return Math.min(Math.max(probability, 15), 95);
  }

  private getDecisionRecommendation(gameState: GameState): string {
    const conversionProb = this.getConversionProbability(gameState);
    const fieldPosition = (gameState.fieldPosition as number) || 50;
    const scoreDiff = Math.abs(gameState.homeScore - gameState.awayScore);
    const timePressure = this.getTimePressureLevel(gameState);

    // High conversion probability situations
    if (conversionProb >= 75) {
      return 'GO_FOR_IT';
    }

    // Critical time situations
    if (timePressure === 'CRITICAL' && scoreDiff <= 7) {
      return fieldPosition <= 40 ? 'GO_FOR_IT' : 'PUNT';
    }

    // Field goal range
    if (fieldPosition <= 35 && conversionProb < 60) {
      return 'FIELD_GOAL_ATTEMPT';
    }

    // Default recommendations
    if (fieldPosition <= 30) return 'GO_FOR_IT';
    if (fieldPosition >= 60) return 'PUNT';

    return conversionProb >= 50 ? 'GO_FOR_IT' : 'PUNT';
  }

  private createDynamicMessage(gameState: GameState): string {
    const yardsToGo = (gameState.yardsToGo as number) || 10;
    const fieldPosition = (gameState.fieldPosition as number) || 50;
    const recommendation = this.getDecisionRecommendation(gameState);
    const conversionProb = this.getConversionProbability(gameState);

    // Create contextual field position description
    let positionDesc = '';
    if (fieldPosition <= 5) {
      positionDesc = `at ${fieldPosition}-yard line`;
    } else if (fieldPosition <= 20) {
      positionDesc = `at ${fieldPosition}-yard line (Red Zone)`;
    } else if (fieldPosition <= 35) {
      positionDesc = `at ${fieldPosition}-yard line (FG Range)`;
    } else if (fieldPosition >= 80) {
      positionDesc = `at own ${100 - fieldPosition}-yard line`;
    } else {
      positionDesc = `at ${fieldPosition}-yard line`;
    }

    // Create decision context
    let decisionContext = '';
    switch (recommendation) {
      case 'GO_FOR_IT':
        decisionContext = conversionProb >= 75 ? 'High conversion chance' : 'Critical decision';
        break;
      case 'FIELD_GOAL_ATTEMPT':
        decisionContext = 'FG attempt likely';
        break;
      case 'PUNT':
        decisionContext = 'Punt situation';
        break;
      default:
        decisionContext = 'Decision pending';
    }

    return `4th & ${yardsToGo} ${positionDesc} - ${decisionContext}`;
  }

  private parseTimeToSeconds(timeString: string): number {
    if (!timeString) return 0;
    const cleanTime = timeString.trim().split(' ')[0];

    if (cleanTime.includes(':')) {
      const [minutes, seconds] = cleanTime.split(':').map(t => parseInt(t) || 0);
      return (minutes * 60) + seconds;
    }

    return parseInt(cleanTime) || 0;
  }
}

shared/schema.ts.content:
import { sql } from "drizzle-orm";
import { pgTable, text, varchar, boolean, timestamp, jsonb, integer, unique, decimal } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";

export const users = pgTable("users", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  username: text("username").unique(),
  email: text("email").unique(),
  password: text("password"),
  // OAuth fields
  googleId: text("google_id").unique(),
  appleId: text("apple_id").unique(),
  firstName: text("first_name"),
  lastName: text("last_name"),
  profileImage: text("profile_image"),
  // Authentication method tracking
  authMethod: text("auth_method").notNull().default("local"), // 'local', 'google', 'apple'
  emailVerified: boolean("email_verified").notNull().default(false),
  // Admin role system
  role: text("role").notNull().default("user"), // 'admin', 'manager', 'analyst', 'user'
  // Individual Telegram configuration
  telegramBotToken: text("telegram_bot_token"),
  telegramChatId: text("telegram_chat_id"),
  telegramEnabled: boolean("telegram_enabled").notNull().default(false),
  // Odds API preferences for enhanced gambling insights
  oddsApiEnabled: boolean("odds_api_enabled").notNull().default(false),
  oddsApiKey: text("odds_api_key"), // User's personal Odds API key (optional)
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow(),
});

export const teams = pgTable("teams", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  name: text("name").notNull(),
  initials: text("initials").notNull(),
  sport: text("sport").notNull(),
  logoColor: text("logo_color").notNull().default("#1D2E5F"),
  monitored: boolean("monitored").notNull().default(false),
  externalId: text("external_id"),
});


export const settings = pgTable("settings", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  sport: text("sport").notNull(),
  preferences: jsonb("preferences").$type<{
    notifications: boolean;
    theme: string;
  }>().notNull(),
  telegramEnabled: boolean("telegram_enabled").notNull().default(false),
  pushNotificationsEnabled: boolean("push_notifications_enabled").notNull().default(false),
});

// User monitored teams for persistent game selection
export const userMonitoredTeams = pgTable("user_monitored_teams", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  userId: varchar("user_id").notNull().references(() => users.id, { onDelete: "cascade" }),
  gameId: text("game_id").notNull(), // The game ID from live sports API
  sport: text("sport").notNull(),
  homeTeamName: text("home_team_name").notNull(),
  awayTeamName: text("away_team_name").notNull(),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Global alert settings for admin management
export const globalAlertSettings = pgTable("global_alert_settings", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  sport: text("sport").notNull(), // MLB, NFL, NBA, CFL, NCAAF, WNBA
  alertType: text("alert_type").notNull(), // RISP, BASES_LOADED, etc.
  enabled: boolean("enabled").notNull().default(true),
  updatedAt: timestamp("updated_at").notNull().defaultNow(),
  updatedBy: varchar("updated_by").references(() => users.id), // Admin who made the change
}, (table) => ({
  // Unique constraint to prevent duplicate (sport, alertType) combinations
  uniqueSportAlertType: unique("unique_sport_alert_type").on(table.sport, table.alertType)
}));

// Alerts table for storing all alerts
export const alerts = pgTable("alerts", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  alertKey: varchar("alert_key").notNull(),
  // Sequence number for preventing data loss on reconnects
  sequenceNumber: integer("sequence_number").notNull().generatedAlwaysAsIdentity(),
  sport: text("sport").notNull(),
  gameId: text("game_id").notNull(),
  type: text("type").notNull(),
  state: text("state").notNull(),
  score: integer("score").notNull().default(0),
  payload: jsonb("payload").notNull(),
  userId: varchar("user_id").references(() => users.id, { onDelete: "cascade" }),
  createdAt: timestamp("created_at").notNull().defaultNow(),
  // Alert persistence: minimum display time to prevent immediate disappearing
  expiresAt: timestamp("expires_at").notNull().default(sql`NOW() + INTERVAL '5 minutes'`),
});


// Insert schemas
export const insertUserSchema = createInsertSchema(users).pick({
  username: true,
  email: true,
  password: true,
  googleId: true,
  appleId: true,
  firstName: true,
  lastName: true,
  profileImage: true,
  authMethod: true,
}).extend({
  // Make fields flexible for different auth methods
  usernameOrEmail: z.string().optional(),
}).partial().refine(
  (data) => {
    // At least username, email, googleId, or appleId must be provided
    return data.username || data.email || data.googleId || data.appleId || data.usernameOrEmail;
  },
  {
    message: "At least one identifier (username, email, Google ID, or Apple ID) is required",
  }
);

export const insertTeamSchema = createInsertSchema(teams).omit({
  id: true,
});


export const insertSettingsSchema = createInsertSchema(settings).omit({
  id: true,
});

export const insertUserMonitoredTeamSchema = createInsertSchema(userMonitoredTeams).omit({
  id: true,
  createdAt: true,
});

export const insertGlobalAlertSettingsSchema = createInsertSchema(globalAlertSettings).omit({
  id: true,
  updatedAt: true,
});


// Types
export type InsertUser = z.infer<typeof insertUserSchema>;
export type User = typeof users.$inferSelect;

export type InsertTeam = z.infer<typeof insertTeamSchema>;
export type Team = typeof teams.$inferSelect;


export type InsertSettings = z.infer<typeof insertSettingsSchema>;
export type Settings = typeof settings.$inferSelect;

export type InsertUserMonitoredTeam = z.infer<typeof insertUserMonitoredTeamSchema>;
export type UserMonitoredTeam = typeof userMonitoredTeams.$inferSelect;

// User alert preferences for individual alert types
export const userAlertPreferences = pgTable("user_alert_preferences", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  userId: varchar("user_id").notNull().references(() => users.id, { onDelete: "cascade" }),
  sport: text("sport").notNull(), // MLB, NFL, NBA, CFL, NCAAF, WNBA
  alertType: text("alert_type").notNull(), // RISP, CLOSE_GAME, etc.
  enabled: boolean("enabled").notNull().default(true),
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow(),
});

export const insertUserAlertPreferencesSchema = createInsertSchema(userAlertPreferences).omit({
  id: true,
  createdAt: true,
  updatedAt: true,
});

export type InsertUserAlertPreferences = z.infer<typeof insertUserAlertPreferencesSchema>;
export type UserAlertPreferences = typeof userAlertPreferences.$inferSelect;

// Alert schemas and types
export const insertAlertSchema = createInsertSchema(alerts).omit({
  id: true,
  createdAt: true,
});

export type InsertAlert = z.infer<typeof insertAlertSchema>;
export type Alert = typeof alerts.$inferSelect;


// Enhanced game states table for storing live game data with player and weather context
export const gameStates = pgTable("game_states", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  extGameId: text("ext_game_id").notNull(), // External game ID from API (e.g., "776362")
  sport: text("sport").notNull(), // MLB, NFL, NBA, etc.
  homeTeam: text("home_team").notNull(),
  awayTeam: text("away_team").notNull(),
  homeScore: integer("home_score").default(0),
  awayScore: integer("away_score").default(0),
  status: text("status").notNull(), // scheduled, live, final
  inning: integer("inning"),
  isTopInning: boolean("is_top_inning"),
  balls: integer("balls").default(0),
  strikes: integer("strikes").default(0),
  outs: integer("outs").default(0),
  // Base runners
  hasFirst: boolean("has_first").default(false),
  hasSecond: boolean("has_second").default(false),
  hasThird: boolean("has_third").default(false),
  // Enhanced player data
  currentBatter: text("current_batter"),
  currentPitcher: text("current_pitcher"),
  onDeckBatter: text("on_deck_batter"),
  // Weather context
  windSpeed: integer("wind_speed"), // mph
  windDirection: text("wind_direction"), // N, NE, E, SE, S, SW, W, NW
  temperature: integer("temperature"), // Fahrenheit
  humidity: integer("humidity"), // percentage
  // Enhanced data payload for flexibility
  enhancedData: jsonb("enhanced_data").$type<{
    lineupData?: any;
    weatherContext?: any;
    gameState?: string;
    lastUpdated?: string;
  }>(),
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow(),
});

export const insertGameStateSchema = createInsertSchema(gameStates).omit({
  id: true,
  createdAt: true,
  updatedAt: true,
});

export type InsertGameState = z.infer<typeof insertGameStateSchema>;
export type GameState = typeof gameStates.$inferSelect;

// Game types for live sports data
export interface Game {
  id: string;
  sport: string;
  homeTeam: {
    id: string;
    name: string;
    abbreviation: string;
    score?: number;
  };
  awayTeam: {
    id: string;
    name: string;
    abbreviation: string;
    score?: number;
  };
  startTime: string;
  status: 'scheduled' | 'live' | 'final';
  venue?: string;
  isSelected?: boolean;
  isLive?: boolean;
  isCompleted?: boolean;
  // MLB-specific fields
  inning?: number;
  inningState?: string;
  gameState?: string;
  gamePk?: number;
  // NFL/NCAAF/CFL-specific fields
  quarter?: number;
  timeRemaining?: string;
  down?: number;
  yardsToGo?: number;
  fieldPosition?: string;
  possession?: string;
  homeTimeoutsRemaining?: number;
  awayTimeoutsRemaining?: number;
  // NBA/WNBA-specific fields
  period?: number;
}

export interface GameDay {
  date: string;
  games: Game[];
}

// Gambling insights interface for enhanced alert data
export interface GamblingInsights {
  structuredTemplate?: string; // New structured format with emojis
  market?: {
    moneyline?: {
      home?: number;
      away?: number;
    };
    spread?: {
      points?: number;
      home?: number;
      away?: number;
    };
    total?: {
      points?: number;
      over?: number;
      under?: number;
    };
  };
  weather?: {
    impact: string;
    conditions: string;
    severity: 'low' | 'medium' | 'high';
  };
  keyPlayers?: {
    name: string;
    position: string;
    relevance: string;
  }[];
  momentum?: {
    recent: string;
    trend: 'positive' | 'negative' | 'neutral';
    timeframe: string;
  };
  situation?: {
    context: string;
    significance: string;
    timing: string;
  };
  bullets?: string[];
  confidence?: number; // 0-1 rating
  tags?: string[];
}

// Enhanced AlertResult interface with gambling insights
export interface AlertResult {
  alertKey: string;
  type: string;
  message: string;
  displayMessage?: string;
  context: any;
  priority: number;
  gamblingInsights?: GamblingInsights;
  hasComposerEnhancement?: boolean;
}

// Zod schema for GamblingInsights validation
export const gamblingInsightsSchema = z.object({
  market: z.object({
    moneyline: z.object({
      home: z.number().optional(),
      away: z.number().optional(),
    }).optional(),
    spread: z.object({
      points: z.number().optional(),
      home: z.number().optional(),
      away: z.number().optional(),
    }).optional(),
    total: z.object({
      points: z.number().optional(),
      over: z.number().optional(),
      under: z.number().optional(),
    }).optional(),
  }).optional(),
  weather: z.object({
    impact: z.string(),
    conditions: z.string(),
    severity: z.enum(['low', 'medium', 'high']),
  }).optional(),
  keyPlayers: z.array(z.object({
    name: z.string(),
    position: z.string(),
    relevance: z.string(),
  })).optional(),
  momentum: z.object({
    recent: z.string(),
    trend: z.enum(['positive', 'negative', 'neutral']),
    timeframe: z.string(),
  }).optional(),
  situation: z.object({
    context: z.string(),
    significance: z.string(),
    timing: z.string(),
  }).optional(),
  bullets: z.array(z.string()).min(1).optional(),
  confidence: z.number().min(0).max(1).optional(),
  tags: z.array(z.string()).optional(),
});

// Zod schema for AlertResult validation
export const alertResultSchema = z.object({
  alertKey: z.string(),
  type: z.string(),
  message: z.string(),
  displayMessage: z.string().optional(),
  context: z.any(),
  priority: z.number(),
  gamblingInsights: gamblingInsightsSchema.optional(),
  hasComposerEnhancement: z.boolean().optional(),
});

// Export types derived from Zod schemas  
export type GamblingInsightsType = z.infer<typeof gamblingInsightsSchema>;
export type AlertResultType = z.infer<typeof alertResultSchema>;

