import fs from 'fs';
import path from 'path';
import os from 'os';
import { createServer } from 'net';

interface LockData {
  pid: number;
  port: number;
  timestamp: number;
}

export class SingleInstanceLock {
  private lockPath: string;
  private lockFd: number | null = null;

  constructor(lockName: string = 'chirpbot') {
    this.lockPath = path.join(os.tmpdir(), `${lockName}.lock`);
  }

  /**
   * Attempts to acquire the lock. Returns true if successful, false if another instance is running.
   */
  async acquire(port: number): Promise<boolean> {
    try {
      // Try to create exclusive lock file
      this.lockFd = fs.openSync(this.lockPath, 'wx');

      const lockData: LockData = {
        pid: process.pid,
        port,
        timestamp: Date.now()
      };

      fs.writeSync(this.lockFd, JSON.stringify(lockData, null, 2));

      // Setup cleanup on process exit
      process.on('exit', () => this.release());
      process.on('SIGINT', () => {
        this.release();
        process.exit(0);
      });
      process.on('SIGTERM', () => {
        this.release();
        process.exit(0);
      });

      return true;
    } catch (error: any) {
      if (error.code === 'EEXIST') {
        // Lock file exists, check if process is still alive
        return await this.handleExistingLock(port);
      }
      throw error;
    }
  }

  private async handleExistingLock(port: number): Promise<boolean> {
    try {
      const lockContent = fs.readFileSync(this.lockPath, 'utf8');
      const lockData: LockData = JSON.parse(lockContent);

      // Check if the process is still alive
      if (this.isProcessAlive(lockData.pid)) {
        // In development mode, kill the old process and take over
        if (process.env.NODE_ENV === 'development') {
          console.log(`🔄 Development restart detected - terminating old process PID ${lockData.pid}...`);

          try {
            // Kill the old process
            process.kill(lockData.pid, 'SIGTERM');
            console.log(`📡 Sent SIGTERM to PID ${lockData.pid}`);

            // Wait for it to die
            await this.waitForProcessToDie(lockData.pid, 5000);

            // If still alive after SIGTERM, force kill with SIGKILL
            if (this.isProcessAlive(lockData.pid)) {
              console.log(`⚠️ PID ${lockData.pid} didn't respond to SIGTERM, sending SIGKILL...`);
              process.kill(lockData.pid, 'SIGKILL');
              await this.waitForProcessToDie(lockData.pid, 2000);
            }

            // Remove the lock file and acquire
            fs.unlinkSync(this.lockPath);
            console.log(`✅ Old process terminated - acquiring lock`);
            return await this.acquire(port);
          } catch (killError: any) {
            console.error(`❌ Failed to kill old process ${lockData.pid}:`, killError.message);
            // If we can't kill it, something is wrong - still try to take over
            fs.unlinkSync(this.lockPath);
            return await this.acquire(port);
          }
        }

        console.log(`🔒 ChirpBot instance already running (PID: ${lockData.pid}, Port: ${lockData.port})`);
        console.log('   Existing instance is healthy - exiting gracefully');
        return false;
      } else {
        // Process is dead, remove stale lock
        console.log(`🧹 Removing stale lock file (PID ${lockData.pid} no longer exists)`);
        fs.unlinkSync(this.lockPath);

        // Try to acquire again
        return await this.acquire(port);
      }
    } catch (error) {
      // Corrupted lock file, remove it
      console.log('🧹 Removing corrupted lock file');
      try {
        fs.unlinkSync(this.lockPath);
      } catch {}
      return await this.acquire(5000); // Try again with default port
    }
  }

  private isProcessAlive(pid: number): boolean {
    try {
      // Signal 0 tests for process existence without actually sending a signal
      process.kill(pid, 0);
      return true;
    } catch (error: any) {
      return error.code !== 'ESRCH'; // ESRCH means process doesn't exist
    }
  }

  /**
   * Waits for a process to die during development restarts
   */
  private async waitForProcessToDie(pid: number, maxWaitMs: number): Promise<void> {
    const start = Date.now();
    const checkInterval = 500; // Check every 500ms

    while (this.isProcessAlive(pid) && (Date.now() - start) < maxWaitMs) {
      await new Promise(resolve => setTimeout(resolve, checkInterval));

      const elapsed = Date.now() - start;
      if (elapsed % 1000 < checkInterval) { // Log every second
        console.log(`⏳ Waiting for PID ${pid} to shutdown... (${Math.floor(elapsed/1000)}s/${Math.floor(maxWaitMs/1000)}s)`);
      }
    }

    if (this.isProcessAlive(pid)) {
      console.log(`⚠️ Process ${pid} still running after ${maxWaitMs}ms wait`);
    } else {
      console.log(`✅ Process ${pid} successfully shutdown`);
    }
  }

  /**
   * Releases the lock and cleans up
   */
  release(): void {
    if (this.lockFd !== null) {
      try {
        fs.closeSync(this.lockFd);
        this.lockFd = null;
      } catch {}
    }

    try {
      fs.unlinkSync(this.lockPath);
    } catch {}
  }

  /**
   * Checks if a port is in use
   */
  static async isPortInUse(port: number, host: string = '0.0.0.0'): Promise<boolean> {
    return new Promise((resolve) => {
      const server = createServer();

      server.listen(port, host, () => {
        server.close(() => resolve(false));
      });

      server.on('error', () => resolve(true));
    });
  }

  /**
   * Waits for a port to become available with exponential backoff
   */
  static async waitForPortAvailable(port: number, maxAttempts: number = 5): Promise<boolean> {
    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      const inUse = await this.isPortInUse(port);

      if (!inUse) {
        return true;
      }

      const delay = Math.min(1000 * Math.pow(2, attempt), 5000); // Cap at 5 seconds
      console.log(`⏳ Port ${port} in use, waiting ${delay}ms before retry (${attempt + 1}/${maxAttempts})`);

      await new Promise(resolve => setTimeout(resolve, delay));
    }

    return false;
  }

  /**
   * Finds the next available port starting from the given port
   */
  static async findAvailablePort(startPort: number): Promise<number> {
    for (let port = startPort; port <= startPort + 100; port++) {
      const inUse = await this.isPortInUse(port);
      if (!inUse) {
        return port;
      }
    }
    throw new Error(`No available ports found in range ${startPort}-${startPort + 100}`);
  }
}

server/services/ai-situation-parser.ts.content:
/**
 * AI Situation Parser Service
 * 
 * Uses OpenAI to extract game situation data (down, distance, field position)
 * from play-by-play text when ESPN's structured data is unavailable.
 */

import { openaiApiCircuit, protectedFetch } from '../middleware/circuit-breaker';

const OPENAI_API_KEY = process.env.OPENAI_API_KEY;

export interface ParsedSituation {
  down: number | null;
  yardsToGo: number | null;
  fieldPosition: number | null;
  possession: string | null;
  confidence: number; // 0-1 scale
  parsedFrom: 'ai' | 'structured';
}

export class AISituationParser {
  private static instance: AISituationParser;
  private parseCache = new Map<string, { data: ParsedSituation; timestamp: number }>();
  private readonly CACHE_TTL = 30000; // 30 second cache
  private apiKeyWarningShown = false;

  private constructor() {
    console.log('🤖 AI Situation Parser: Initialized');
  }

  static getInstance(): AISituationParser {
    if (!AISituationParser.instance) {
      AISituationParser.instance = new AISituationParser();
    }
    return AISituationParser.instance;
  }

  /**
   * Parse play-by-play text to extract situation data using OpenAI
   */
  async parseSituationFromText(
    playText: string,
    gameId: string,
    homeTeamAbbrev: string,
    awayTeamAbbrev: string
  ): Promise<ParsedSituation> {
    // Check if OpenAI API key is configured
    if (!OPENAI_API_KEY) {
      if (!this.apiKeyWarningShown) {
        console.warn('⚠️ AI Parser: OPENAI_API_KEY not configured, AI parsing disabled');
        this.apiKeyWarningShown = true;
      }
      return {
        down: null,
        yardsToGo: null,
        fieldPosition: null,
        possession: null,
        confidence: 0,
        parsedFrom: 'ai'
      };
    }

    // Check cache first
    const cacheKey = `${gameId}_${playText}`;
    const cached = this.parseCache.get(cacheKey);
    if (cached && Date.now() - cached.timestamp < this.CACHE_TTL) {
      console.log(`💾 AI Parser: Using cached situation for ${gameId}`);
      return cached.data;
    }

    try {
      console.log(`🤖 AI Parser: Analyzing play text for game ${gameId}: "${playText.substring(0, 100)}..."`);

      const prompt = `Extract game situation data from this NFL play-by-play text.

Play: "${playText}"
Home Team: ${homeTeamAbbrev}
Away Team: ${awayTeamAbbrev}

Extract:
1. down (1-4, or null if not mentioned)
2. yardsToGo (yards needed for first down, or null)
3. fieldPosition (yard line 0-99, where 50 is midfield, or null)
4. possession (team abbreviation who has the ball: "${homeTeamAbbrev}" or "${awayTeamAbbrev}", or null)

Examples:
- "3rd and 7 at MIA 35" → down=3, yardsToGo=7, fieldPosition=35, possession=MIA
- "1st and 10 at NYJ 42" → down=1, yardsToGo=10, fieldPosition=42, possession=NYJ
- "2nd and goal at the 5" → down=2, yardsToGo=null, fieldPosition=5, possession=(team on offense)

Return ONLY a JSON object with these exact fields:
{
  "down": number or null,
  "yardsToGo": number or null,
  "fieldPosition": number or null,
  "possession": string or null,
  "confidence": number 0-1
}`;

      const response = await protectedFetch(
        openaiApiCircuit,
        'https://api.openai.com/v1/chat/completions',
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${OPENAI_API_KEY}`
          },
          body: JSON.stringify({
            model: 'gpt-4o',
            messages: [
              {
                role: 'system',
                content: 'You are an NFL data extraction expert. Extract structured game situation data from play-by-play text. Return only valid JSON.'
              },
              {
                role: 'user',
                content: prompt
              }
            ],
            response_format: { type: 'json_object' },
            temperature: 0.1,
            max_tokens: 150
          })
        }
      );

      if (!response.ok) {
        throw new Error(`OpenAI API error: ${response.status} ${response.statusText}`);
      }

      const data = await response.json();
      const content = data.choices?.[0]?.message?.content;
      if (!content) {
        throw new Error('Empty response from OpenAI');
      }

      const parsed = JSON.parse(content);

      const result: ParsedSituation = {
        down: parsed.down !== undefined ? parsed.down : null,
        yardsToGo: parsed.yardsToGo !== undefined ? parsed.yardsToGo : null,
        fieldPosition: parsed.fieldPosition !== undefined ? parsed.fieldPosition : null,
        possession: parsed.possession || null,
        confidence: parsed.confidence || 0.8,
        parsedFrom: 'ai'
      };

      console.log(`✅ AI Parser: Extracted situation - down=${result.down}, yardsToGo=${result.yardsToGo}, fieldPosition=${result.fieldPosition}, confidence=${result.confidence}`);

      // Cache the result
      this.parseCache.set(cacheKey, { data: result, timestamp: Date.now() });

      // Clean up old cache entries
      this.cleanupCache();

      return result;
    } catch (error) {
      console.error('❌ AI Parser: Error parsing situation:', error);

      // Return null data on error
      return {
        down: null,
        yardsToGo: null,
        fieldPosition: null,
        possession: null,
        confidence: 0,
        parsedFrom: 'ai'
      };
    }
  }

  /**
   * Clean up expired cache entries
   */
  private cleanupCache(): void {
    const now = Date.now();
    for (const [key, value] of this.parseCache.entries()) {
      if (now - value.timestamp > this.CACHE_TTL) {
        this.parseCache.delete(key);
      }
    }
  }

  /**
   * Clear all cache
   */
  clearCache(): void {
    this.parseCache.clear();
    console.log('🧹 AI Parser: Cache cleared');
  }

  /**
   * Get cache statistics
   */
  getCacheStats(): { size: number; ttl: number } {
    return {
      size: this.parseCache.size,
      ttl: this.CACHE_TTL
    };
  }
}

