import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';

export default class GameStartModule extends BaseAlertModule {
  alertType = 'NBA_GAME_START';
  sport = 'NBA';

  // Track game states to detect transitions (gameId -> last known state)
  private gameStates: Map<string, { status: string, hasTriggered: boolean }> = new Map();

  isTriggered(gameState: GameState): boolean {
    if (!gameState.gameId) return false;

    const currentState = this.gameStates.get(gameState.gameId);
    const isLiveGame = gameState.status === 'live' && 
                      gameState.quarter === 1 && 
                      this.parseTimeToSeconds(gameState.timeRemaining) < (12 * 60); // Clock has started (less than 12:00)

    // Only trigger if game is now live AND we haven't triggered for this game yet
    if (isLiveGame) {
      // If we haven't seen this game before, or if we've seen it but it wasn't live before
      if (!currentState || (!currentState.hasTriggered)) {
        // Update our tracking
        this.gameStates.set(gameState.gameId, { 
          status: 'live',
          hasTriggered: true 
        });
        return true;
      }
    } else {
      // Game is not live yet, track it but don't trigger
      if (!currentState) {
        this.gameStates.set(gameState.gameId, { 
          status: gameState.status || 'scheduled',
          hasTriggered: false 
        });
      }
    }

    return false;
  }

  generateAlert(gameState: GameState): AlertResult | null {
    // isTriggered() already called by engine - removed duplicate check
    const timeRemaining = gameState.timeRemaining || '12:00';

    return {
      alertKey: `${gameState.gameId}_nba_game_start`,
      type: this.alertType,
      message: `🏀 NBA TIP-OFF! ${gameState.awayTeam} @ ${gameState.homeTeam} - Game is underway!`,
      context: {
        gameId: gameState.gameId,
        homeTeam: gameState.homeTeam,
        awayTeam: gameState.awayTeam,
        homeScore: gameState.homeScore,
        awayScore: gameState.awayScore,
        quarter: gameState.quarter,
        timeRemaining,
        // NBA-specific context
        nbaContext: {
          isGameStart: true,
          quarter: 'First Quarter',
          shotClock: 24,
          professionalBasketball: true,
          leagueLevel: 'NBA'
        }
      },
      priority: 80
    };
  }

  calculateProbability(gameState: GameState): number {
    return this.isTriggered(gameState) ? 95 : 0;
  }

  private parseTimeToSeconds(timeString: string): number {
    if (!timeString || timeString === '0:00') return 0;

    try {
      const cleanTime = timeString.trim().split(' ')[0];
      if (cleanTime.includes(':')) {
        const [minutes, seconds] = cleanTime.split(':').map(t => parseInt(t) || 0);
        return (minutes * 60) + seconds;
      }
      return parseInt(cleanTime) || 0;
    } catch (error) {
      return 0;
    }
  }
}

