import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';


export default class FourthQuarterModule extends BaseAlertModule {
  alertType = 'NCAAF_FOURTH_QUARTER';
  sport = 'NCAAF';

  // Track which games have triggered Q4 alert
  private q4Triggered: Set<string> = new Set();

  isTriggered(gameState: GameState): boolean {
    console.log(`🔍 NCAAF Fourth Quarter check for ${gameState.gameId}: status=${gameState.status}, Q${gameState.quarter}`);

    // Must be a live game
    if (gameState.status !== 'live') {
      console.log(`❌ Fourth Quarter: Game not live (${gameState.status})`);
      return false;
    }

    // Must be in fourth quarter
    if (gameState.quarter !== 4) {
      console.log(`❌ Fourth Quarter: Not in Q4 (Q${gameState.quarter})`);
      return false;
    }

    // Check if we've already triggered for this game
    if (this.q4Triggered.has(gameState.gameId)) {
      console.log(`❌ Fourth Quarter: Already triggered for ${gameState.gameId}`);
      return false;
    }

    console.log(`🎯 NCAAF FOURTH QUARTER TRIGGERED for ${gameState.gameId}`);
    this.q4Triggered.add(gameState.gameId);
    return true;
  }

  generateAlert(gameState: GameState): AlertResult | null {
    const scoreDiff = Math.abs(gameState.homeScore - gameState.awayScore);
    const isCloseGame = scoreDiff <= 14;

    return {
      alertKey: `${gameState.gameId}_fourth_quarter_start`,
      type: this.alertType,
      message: `${gameState.awayTeam} @ ${gameState.homeTeam} | ${this.createDynamicMessage(gameState, scoreDiff, isCloseGame)}`,
      displayMessage: `🏈 ${this.createDynamicMessage(gameState, scoreDiff, isCloseGame)} | Q${gameState.quarter}`,

      context: {
        gameId: gameState.gameId,
        homeTeam: gameState.homeTeam,
        awayTeam: gameState.awayTeam,
        homeScore: gameState.homeScore,
        awayScore: gameState.awayScore,
        quarter: 4,
        timeRemaining: gameState.timeRemaining,
        scoreDifference: scoreDiff,
        isCloseGame
      },
      priority: isCloseGame ? 90 : 85
    };
  }

  calculateProbability(gameState: GameState): number {
    if (!this.isTriggered(gameState)) return 0;

    // Higher probability for close games
    const scoreDiff = Math.abs(gameState.homeScore - gameState.awayScore);
    if (scoreDiff <= 7) return 95;
    if (scoreDiff <= 14) return 85;
    return 75;
  }

  private createDynamicMessage(gameState: GameState, scoreDiff: number, isCloseGame: boolean): string {
    const timeRemaining = gameState.timeRemaining;

    if (isCloseGame) {
      if (scoreDiff === 0) {
        return `Tied entering Q4 - ${timeRemaining} to decide it`;
      } else {
        return `${scoreDiff}-point game entering Q4 - Crunch time`;
      }
    } else {
      return `Fourth quarter begins - ${timeRemaining} remaining`;
    }
  }
}

import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';

type NormStatus = 'scheduled' | 'live' | 'final' | 'other';

export default class ComebackPotentialModule extends BaseAlertModule {
  alertType = 'WNBA_COMEBACK_POTENTIAL';
  sport = 'WNBA';

  // --- Tunables / config -----------------------------------------------------
  private readonly QUARTER_SECONDS = 600;  // WNBA regulation quarter
  private readonly OT_SECONDS = 300;       // WNBA OT period
  private readonly MIN_DEFICIT_TO_CARE = 3;

  // Quarter-specific “interesting” deficit bands (for the *trailing* team)
  private readonly DEFICIT_BANDS = {
    2: { min: 10, max: 20 }, // early
    3: { min:  8, max: 18 }, // mid
    4: { min:  5, max: 15 }, // late
    5: { min:  1, max:  8 }, // OT
  } as const;

  private readonly BASE_COMEBACK_PROB_BY_Q = {
    1: 0.75, 2: 0.65, 3: 0.45, 4: 0.25, 5: 0.15,
  } as const;

  private readonly FACTORS = {
    THREE_POINT_IMPACT: 3.2,
    PACE_PER_MIN: 1.8,              // estimated possessions per minute (per team-ish)
    TIMEOUT_VALUE: 2.5,
    FOUL_STRATEGY_SEC: 90,
    BENCH_DEPTH: 0.9,
    MOMENTUM_WEIGHT: 1.4,
  };

  // Anti-spam: require condition to persist this long before (re)firing
  private readonly PERSISTENCE_SEC = 20;

  // Track when scenario condition first became true to enforce persistence
  private readonly firstSeenTrue = new Map<string, number>();

  // --- Helpers ---------------------------------------------------------------
  private normStatus(s?: string): NormStatus {
    const t = (s || '').trim().toLowerCase();
    if (t === 'live' || t === 'in progress' || t === 'inprogress') return 'live';
    if (t === 'final' || t === 'completed') return 'final';
    if (t === 'scheduled' || t === 'pregame' || t === 'pre') return 'scheduled';
    return 'other';
  }

  private parseTimeToSeconds(timeString?: string): number {
    if (!timeString || timeString === '0:00') return 0;
    try {
      const clean = timeString.trim().split(' ')[0];
      if (clean.includes(':')) {
        const [m, s] = clean.split(':').map(n => parseInt(n, 10) || 0);
        return m * 60 + s;
      }
      return parseInt(clean, 10) || 0;
    } catch {
      return 0;
    }
  }

  private getDeficitAndTeams(gs: GameState) {
    const home = gs.homeScore ?? 0;
    const away = gs.awayScore ?? 0;
    const trailingTeam = home < away ? gs.homeTeam : gs.awayTeam;
    const leadingTeam  = home > away ? gs.homeTeam : gs.awayTeam;
    const trailingScore = Math.min(home, away);
    const leadingScore  = Math.max(home, away);
    const deficit = leadingScore - trailingScore; // ALWAYS a trailing deficit
    return { trailingTeam, leadingTeam, trailingScore, leadingScore, deficit };
  }

  private totalRegulationTimeLeft(quarter: number, secLeftThisQuarter: number): number {
    if (quarter >= 5) return secLeftThisQuarter; // OT: just use current OT time
    const quartersRemainingAfterThis = Math.max(0, 4 - quarter);
    return secLeftThisQuarter + quartersRemainingAfterThis * this.QUARTER_SECONDS;
  }

  private scenarioKey(gs: GameState, bandLabel: string): string {
    const q = gs.quarter ?? 1;
    // Bucket deficit/time a bit to avoid overly-unique keys
    const { deficit } = this.getDeficitAndTeams(gs);
    const defBucket = Math.min(20, Math.max(0, Math.round(deficit / 2) * 2));
    const timeBucket = Math.min(600, Math.max(0, Math.round(this.parseTimeToSeconds(gs.timeRemaining || '') / 15) * 15));
    return `${gs.gameId}_${bandLabel}_Q${q}_D${defBucket}_T${timeBucket}`;
  }

  private withinBand(q: number, deficit: number): { ok: boolean; label: string } {
    const band = (this.DEFICIT_BANDS as any)[q];
    if (!band) return { ok: false, label: 'NONE' };
    const ok = deficit >= band.min && deficit <= band.max;
    const label = q === 2 ? 'EARLY' : q === 3 ? 'MID' : q === 4 ? 'LATE' : 'OT';
    return { ok, label };
  }

  // --- Core contract ---------------------------------------------------------
  isTriggered(gs: GameState): boolean {
    if (!gs.gameId) return false;
    if (this.normStatus(gs.status) !== 'live') return false;

    const q = gs.quarter ?? 1;
    const tQ = this.parseTimeToSeconds(gs.timeRemaining || '');
    const { deficit } = this.getDeficitAndTeams(gs);

    // Must be a *trailing* deficit above minimal noise
    if (deficit < this.MIN_DEFICIT_TO_CARE) return false;

    const { ok, label } = this.withinBand(q, deficit);
    if (!ok) return false;

    const key = this.scenarioKey(gs, label);

    // Persistence window to avoid flapping
    const now = Date.now();
    if (!this.firstSeenTrue.has(key)) this.firstSeenTrue.set(key, now);
    const seenSince = (now - (this.firstSeenTrue.get(key) || now)) / 1000;

    if (seenSince < this.PERSISTENCE_SEC) return false;

    // Optional: In very late Q4, tighten minimal deficit to avoid garbage time noise
    if (q === 4 && tQ < 90 && deficit < 4) return false;

    return true;
  }

  generateAlert(gs: GameState): AlertResult | null {
    const q = gs.quarter ?? 1;
    const tStr = gs.timeRemaining || '';
    const tSec = this.parseTimeToSeconds(tStr);
    const { trailingTeam, leadingTeam, trailingScore, leadingScore, deficit } = this.getDeficitAndTeams(gs);

    const scenario = this.identifyScenario(q, tSec);
    const probPct  = Math.round(this.probabilityPct(gs));
    const reqPace  = Math.round(this.requiredPointsPerPoss(gs) * 10) / 10;
    const strategies = this.getStrategies(q, tSec, deficit);
    const timeMeta   = this.timeMeta(q, tSec);

    return {
      alertKey: `${gs.gameId}_cb_${scenario}_${q}_${Math.min(20, deficit)}_${Math.min(600, tSec)}`,
      type: this.alertType,
      message: `🔄 COMEBACK: ${trailingTeam} trails ${leadingScore}-${trailingScore} (${deficit}) with ${tStr} left — ${this.scenarioDescription(scenario)}`,
      context: {
        gameId: gs.gameId,
        sport: this.sport,
        homeTeam: gs.homeTeam,
        awayTeam: gs.awayTeam,
        homeScore: gs.homeScore ?? 0,
        awayScore: gs.awayScore ?? 0,
        quarter: q,
        timeRemaining: tStr,
        deficit,
        trailingTeam,
        leadingTeam,
        trailingScore,
        leadingScore,
        comebackScenario: scenario,
        comebackProbability: probPct,
        requiredPace: reqPace,
        keyStrategies: strategies,
        timeFactors: timeMeta,
        alertType: 'PREDICTIVE',
        predictionCategory: 'COMEBACK_POTENTIAL',
        wnbaContext: {
          isComebackScenario: true,
          deficitSize: this.categorizeDeficit(deficit),
          timeUrgency: this.timeUrgency(q, tSec),
          possessionsRemaining: this.estimatePoss(q, tSec),
          requiredThreePointers: Math.ceil(deficit / this.FACTORS.THREE_POINT_IMPACT),
          foulStrategyRecommended: this.shouldFoul(q, tSec, deficit),
          timeoutValue: this.FACTORS.TIMEOUT_VALUE,
          paceFactors: this.FACTORS,
          momentumIndicators: this.momentum(gs),
          strategicOptions: this.strategicOptions(q, tSec, deficit),
        },
      },
      priority: this.priority(probPct, q, deficit, tSec),
    };
  }

  // PURE — do not call isTriggered() here
  calculateProbability(gs: GameState): number {
    return Math.min(Math.max(this.probabilityPct(gs), 10), 85);
  }

  // --- Reasoning pieces used by both methods --------------------------------
  private probabilityPct(gs: GameState): number {
    const q = gs.quarter ?? 1;
    const tSec = this.parseTimeToSeconds(gs.timeRemaining || '');
    const { deficit } = this.getDeficitAndTeams(gs);

    let base = (this.BASE_COMEBACK_PROB_BY_Q as any)[q] ?? 0.25;

    // Deficit shaping (smaller deficit => higher)
    if (deficit <= 5) base *= 1.5;
    else if (deficit <= 8) base *= 1.2;
    else if (deficit <= 12) base *= 1.0;
    else if (deficit <= 15) base *= 0.8;
    else base *= 0.6;

    // Time shaping for Q4/OT
    if (q === 4) {
      if (tSec > 480) base *= 1.1;
      else if (tSec > 300) base *= 1.0;
      else if (tSec > 120) base *= 0.9;
      else base *= 0.7;
    } else if (q >= 5) {
      base *= 0.6;
    }

    return base * 100;
  }

  private requiredPointsPerPoss(gs: GameState): number {
    const q = gs.quarter ?? 1;
    const tSec = this.parseTimeToSeconds(gs.timeRemaining || '');
    const { deficit } = this.getDeficitAndTeams(gs);

    const regLeft = this.totalRegulationTimeLeft(q, tSec);
    const possRemaining = this.estimatePossFromSeconds(regLeft);
    if (possRemaining <= 0) return deficit; // avoid div-by-zero; treat as all in one shot
    return deficit / possRemaining;
  }

  private estimatePoss(q: number, tSec: number): number {
    return Math.round(this.estimatePossFromSeconds(this.totalRegulationTimeLeft(q, tSec)));
  }

  private estimatePossFromSeconds(seconds: number): number {
    // Rough combined-team possessions available to the *trailing* team
    const perMin = this.FACTORS.PACE_PER_MIN;
    return (seconds / 60) * perMin;
  }

  private identifyScenario(q: number, tSec: number): string {
    if (q >= 5) return 'OVERTIME_COMEBACK';
    if (q === 4 && tSec <= 120) return 'FINAL_MINUTES_RALLY';
    if (q === 4 && tSec <= 300) return 'FOURTH_QUARTER_COMEBACK';
    if (q === 3) return 'MID_GAME_RALLY';
    if (q === 2) return 'EARLY_COMEBACK';
    return 'COMEBACK_OPPORTUNITY';
  }

  private scenarioDescription(s: string): string {
    switch (s) {
      case 'OVERTIME_COMEBACK': return 'Overtime chance developing';
      case 'FINAL_MINUTES_RALLY': return 'Final two-minute push';
      case 'FOURTH_QUARTER_COMEBACK': return 'Late-game comeback window';
      case 'MID_GAME_RALLY': return 'Mid-game rally opportunity';
      case 'EARLY_COMEBACK': return 'Early deficit—plenty of time';
      default: return 'Comeback opportunity';
    }
  }

  private getStrategies(q: number, tSec: number, deficit: number): string[] {
    const s: string[] = [];
    if (deficit >= 6) s.push('Lean into quality 3s');
    if (q >= 3) s.push('Tighten on-ball defense');
    if (q === 4 && tSec <= this.FACTORS.FOUL_STRATEGY_SEC) s.push('Consider foul-to-extend');
    if (q >= 3) s.push('Use timeouts strategically');
    if (deficit >= 8) s.push('Increase pace selectively');
    s.push('Dominate the defensive glass');
    return s;
  }

  private timeMeta(q: number, tSec: number) {
    return {
      quarterPhase: q <= 2 ? 'early' : q === 3 ? 'middle' : q === 4 ? 'late' : 'overtime',
      timeUrgency: this.timeUrgency(q, tSec),
      possessionsRemaining: this.estimatePoss(q, tSec),
      canAffordTurnovers: q <= 3 || (q === 4 && tSec > 180),
      timeForPatience: q <= 2,
      mustPressNow: q === 4 && tSec <= 300,
    };
  }

  private categorizeDeficit(d: number): string {
    if (d <= 3) return 'minimal';
    if (d <= 6) return 'small';
    if (d <= 10) return 'moderate';
    if (d <= 15) return 'large';
    return 'substantial';
  }

  private timeUrgency(q: number, tSec: number): string {
    if (q >= 5) return 'extreme';
    if (q === 4 && tSec <= 60) return 'critical';
    if (q === 4 && tSec <= 180) return 'high';
    if (q === 4 && tSec <= 360) return 'moderate';
    if (q >= 3) return 'low';
    return 'minimal';
  }

  private shouldFoul(q: number, tSec: number, deficit: number): boolean {
    return q === 4 && tSec <= this.FACTORS.FOUL_STRATEGY_SEC && deficit >= 4;
  }

  private momentum(_gs: GameState) {
    // Placeholder – wire to recent run data when available
    return {
      recentTrend: 'neutral',
      momentumShift: true, // conservative optimistic flag for UI
      energyLevel: 'high',
      crowdFactor: 'supportive',
    };
  }

  private strategicOptions(q: number, tSec: number, deficit: number): string[] {
    const opts = ['Defensive pressure', 'High-value 3s'];
    if (q >= 3) opts.push('Timeout sequencing');
    if (q === 4 && tSec <= 120) opts.push('Foul-to-extend clock');
    if (deficit >= 8) opts.push('Press defense');
    if (q >= 4) opts.push('Targeted substitutions');
    return opts;
  }

  private priority(probPct: number, q: number, deficit: number, tSec: number): number {
    let p = 80;
    p += Math.round(probPct * 0.1);
    if (q >= 5) p += 8;
    else if (q === 4) p += 5;
    else if (q === 3) p += 3;

    if (deficit <= 5) p += 8;
    else if (deficit <= 8) p += 5;
    else if (deficit <= 12) p += 3;

    if (q === 4 && tSec <= 300) p += 5;
    return Math.min(p, 95);
  }
}

import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';

export default class GameStartModule extends BaseAlertModule {
  alertType = 'NFL_GAME_START';
  sport = 'NFL';

  // Track game states to detect transitions (gameId -> last known state)
  private gameStates: Map<string, { status: string, hasTriggered: boolean }> = new Map();

  isTriggered(gameState: GameState): boolean {
    if (!gameState.gameId) return false;

    const currentState = this.gameStates.get(gameState.gameId);
    const isActualGameStart = gameState.status === 'live' && gameState.quarter === 1; // Only Q1

    // Only trigger if game is now live in Q1 AND we haven't triggered for this game yet
    if (isActualGameStart) {
      // If we haven't seen this game before, or if we've seen it but it wasn't live before
      if (!currentState || (!currentState.hasTriggered)) {
        // Update our tracking
        this.gameStates.set(gameState.gameId, {
          status: 'live',
          hasTriggered: true
        });
        return true;
      }
    } else {
      // Game is not live yet, track it but don't trigger
      if (!currentState) {
        this.gameStates.set(gameState.gameId, {
          status: gameState.status || 'scheduled',
          hasTriggered: false
        });
      }
    }

    return false;
  }

  generateAlert(gameState: GameState): AlertResult | null {
    // Fire for any early game situation - removed exact timing requirement
    // No restrictions - alert for any game start scenario

    const alertKey = `nfl_game_start_${gameState.gameId}`;

    // Rich NFL game start context
    const context = {
      gameId: gameState.gameId,
      sport: 'NFL',
      quarter: gameState.quarter,
      homeTeam: gameState.homeTeam,
      awayTeam: gameState.awayTeam,

      // NFL-specific strategic context
      reasons: [
        'Opening drive sets tone - 73% of teams scoring first TD win',
        'Fresh game plans before in-game adjustments',
        'Weather conditions locked for 3+ hours',
        'Prime betting value before line movement'
      ],

      // Betting opportunities
      bettingOpportunities: [
        'First TD scorer props at maximum odds',
        'Opening drive result props available',
        'First quarter totals at opening lines',
        'Team total props before weather impact'
      ],

      // Game flow expectations
      gameFlow: {
        expectedDuration: '3 hours 12 minutes',
        paceExpectation: 'Methodical early, accelerated late',
        keyMoments: ['Opening drive', 'First turnover', 'Red zone efficiency'],
        momentum: 'Neutral - coaching game plans vs execution'
      },

      // Strategic factors
      strategicFactors: [
        'Home field crowd noise advantage',
        'Weather impact on passing vs running',
        'Injury report considerations locked in',
        'Coaching tendencies: conservative vs aggressive start'
      ],

      // Weather and field conditions
      fieldConditions: gameState.weatherContext ? {
        temperature: `${(gameState.weatherContext as any).temperature}°F`,
        wind: `${(gameState.weatherContext as any).windSpeed}mph ${(gameState.weatherContext as any).windDirection || ''}`,
        impact: (gameState.weatherContext as any).windSpeed > 15 ? 'Significant passing impact' : 'Minimal weather factor'
      } : {
        conditions: 'Dome/controlled environment',
        impact: 'Weather neutral - pure skill matchup'
      },

      // Time sensitivity
      urgency: 'Kickoff imminent - final window for optimal prop betting',

      // Historical context
      historical: 'NFL game start props show 78% accuracy in first quarter betting',

      // Key matchup factors
      matchupFactors: [
        'Offensive line vs pass rush sets game pace',
        'Secondary vs receivers determines deep ball success',
        'Running game efficiency affects clock management',
        'Special teams field position battle crucial'
      ]
    };

    const dynamicMessage = this.createDynamicMessage(gameState);

    return {
      alertKey,
      type: this.alertType,
      priority: 75,
      message: `${gameState.awayTeam} @ ${gameState.homeTeam} | ${dynamicMessage}`,
      displayMessage: `🏈 ${dynamicMessage} | Q${gameState.quarter}`,
      context
    };
  }

  calculateProbability(gameState: GameState): number {
    return this.isTriggered(gameState) ? 100 : 0;
  }

  private createDynamicMessage(gameState: GameState): string {
    // Create contextual game situation
    let situationDesc = 'Game starting';

    // Add weather context if available
    if (gameState.weatherContext) {
      const weather = gameState.weatherContext as any;
      let weatherDesc = '';

      if (weather.temperature !== undefined) {
        if (weather.temperature <= 32) {
          weatherDesc = `${weather.temperature}°F freezing conditions`;
        } else if (weather.temperature >= 90) {
          weatherDesc = `${weather.temperature}°F hot conditions`;
        } else if (weather.windSpeed && weather.windSpeed >= 20) {
          weatherDesc = `${weather.windSpeed}mph winds`;
        }
      }

      if (weather.condition && weather.condition.toLowerCase() !== 'clear') {
        weatherDesc = weatherDesc ? `${weatherDesc}, ${weather.condition}` : weather.condition;
      }

      if (weatherDesc) {
        situationDesc = `Game starting in ${weatherDesc}`;
      }
    }

    // Add score context if this is a restart or continuation
    if (gameState.homeScore > 0 || gameState.awayScore > 0) {
      const scoreText = gameState.homeScore === gameState.awayScore ? 
        `Tied ${gameState.homeScore}-${gameState.awayScore}` :
        `${gameState.homeScore}-${gameState.awayScore}`;
      situationDesc = `Game resuming - ${scoreText}`;
    }

    // Add quarter context for specific situations
    if (gameState.quarter === 1) {
      situationDesc = situationDesc.replace('Game starting', 'Kickoff time');
    } else if (gameState.quarter === 2) {
      situationDesc = situationDesc.replace('Game starting', '2nd quarter beginning');
    }

    return situationDesc;
  }

  private parseTimeToSeconds(timeString: string): number {
    if (!timeString || timeString === '0:00') return 0;

    try {
      const cleanTime = timeString.trim().split(' ')[0];
      if (cleanTime.includes(':')) {
        const [minutes, seconds] = cleanTime.split(':').map(t => parseInt(t) || 0);
        return (minutes * 60) + seconds;
      }
      return parseInt(cleanTime) || 0;
    } catch (error) {
      return 0;
    }
  }
}

public/admin/styles.css.content:
/* Admin Dashboard Styles */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Inter', sans-serif;
    background: linear-gradient(135deg, #0f172a 0%, #1e293b 50%, #334155 100%);
    color: #f8fafc;
    min-height: 100vh;
}

/* Login Page Styles */
.login-page {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    padding: 20px;
}

.login-container {
    width: 100%;
    max-width: 450px;
}

.login-card {
    background: rgba(30, 41, 59, 0.95);
    backdrop-filter: blur(20px);
    border: 1px solid rgba(148, 163, 184, 0.2);
    border-radius: 20px;
    padding: 40px;
    box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.8);
}

.login-header {
    text-align: center;
    margin-bottom: 40px;
}

.logo {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 15px;
    margin-bottom: 10px;
}

.logo i {
    font-size: 40px;
    color: #fbbf24;
    text-shadow: 0 0 20px rgba(251, 191, 36, 0.5);
}

.logo h1 {
    font-size: 28px;
    font-weight: 700;
    color: #f8fafc;
    letter-spacing: -0.5px;
}

.subtitle {
    color: #94a3b8;
    font-size: 16px;
    font-weight: 500;
}

.login-form {
    margin-bottom: 30px;
}

.form-group {
    margin-bottom: 25px;
}

.form-group label {
    display: block;
    margin-bottom: 8px;
    font-weight: 600;
    color: #e2e8f0;
    font-size: 14px;
}

.input-wrapper {
    position: relative;
}

.input-wrapper i {
    position: absolute;
    left: 16px;
    top: 50%;
    transform: translateY(-50%);
    color: #64748b;
    font-size: 16px;
}

.input-wrapper input {
    width: 100%;
    padding: 16px 16px 16px 50px;
    border: 2px solid rgba(148, 163, 184, 0.2);
    border-radius: 12px;
    background: rgba(15, 23, 42, 0.6);
    color: #f8fafc;
    font-size: 16px;
    font-weight: 500;
    transition: all 0.3s ease;
}

.input-wrapper input:focus {
    outline: none;
    border-color: #3b82f6;
    box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.1);
    background: rgba(15, 23, 42, 0.9);
}

.input-wrapper input::placeholder {
    color: #64748b;
}

.toggle-password {
    position: absolute;
    right: 16px;
    top: 50%;
    transform: translateY(-50%);
    background: none;
    border: none;
    color: #64748b;
    cursor: pointer;
    font-size: 16px;
    transition: color 0.3s ease;
}

.toggle-password:hover {
    color: #94a3b8;
}

.error-message {
    background: rgba(239, 68, 68, 0.1);
    border: 1px solid rgba(239, 68, 68, 0.3);
    color: #fca5a5;
    padding: 12px 16px;
    border-radius: 8px;
    margin-bottom: 20px;
    font-size: 14px;
    display: flex;
    align-items: center;
    gap: 8px;
}

.error-message::before {
    content: "⚠";
    font-weight: bold;
}

.login-btn {
    width: 100%;
    padding: 16px;
    background: linear-gradient(135deg, #3b82f6 0%, #1d4ed8 100%);
    border: none;
    border-radius: 12px;
    color: white;
    font-size: 16px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    box-shadow: 0 4px 20px rgba(59, 130, 246, 0.3);
}

.login-btn:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 30px rgba(59, 130, 246, 0.4);
}

.login-btn:active {
    transform: translateY(0);
}

.login-btn:disabled {
    opacity: 0.6;
    cursor: not-allowed;
    transform: none;
}

.login-footer {
    text-align: center;
}

.security-notice {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    background: rgba(59, 130, 246, 0.1);
    border: 1px solid rgba(59, 130, 246, 0.2);
    padding: 12px 16px;
    border-radius: 8px;
    margin-bottom: 20px;
    font-size: 13px;
    color: #93c5fd;
}

.back-link {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    color: #94a3b8;
    text-decoration: none;
    font-size: 14px;
    transition: color 0.3s ease;
}

.back-link:hover {
