import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';


export default class MassiveWeatherModule extends BaseAlertModule {
  alertType = 'NFL_MASSIVE_WEATHER';
  sport = 'NFL';

  // Track previous weather conditions per game
  private previousWeatherData: { 
    [gameId: string]: { 
      condition: string;
      precipitation: boolean;
      severity: number;
    } 
  } = {};

  // Alert thresholds for severe weather
  private readonly SEVERE_WEATHER_CONDITIONS = [
    'thunderstorm', 'heavy rain', 'storm', 'severe', 'tornado',
    'lightning', 'downpour', 'deluge', 'tempest'
  ];

  isTriggered(gameState: GameState): boolean {
    // Only check for live games or games starting soon
    if (!gameState.isLive && gameState.status !== 'scheduled') return false;
    if (!gameState.weatherContext) return false;

    const gameId = gameState.gameId;
    const currentWeather = gameState.weatherContext;

    const previous = this.previousWeatherData[gameId];

    // Analyze weather condition for severity
    const currentCondition = ((currentWeather as any).condition as string | undefined)?.toLowerCase() || '';
    const currentSeverity = this.calculateWeatherSeverity(currentCondition, currentWeather);

    // First measurement for this game
    if (!previous) {
      this.previousWeatherData[gameId] = {
        condition: currentCondition,
        precipitation: this.hasPrecipitation(currentCondition),
        severity: currentSeverity
      };

      // Alert immediately if any weather is detected
      return currentSeverity >= 1; // Any weather threshold
    }

    // Determine if weather change is significant enough for alert
    const severityIncrease = currentSeverity - previous.severity;
    // Alert on any weather change - removed severity barriers
    if (currentSeverity > previous.severity || severityIncrease >= 1) {
      // Update data
      this.previousWeatherData[gameId] = {
        condition: currentCondition,
        precipitation: this.hasPrecipitation(currentCondition),
        severity: currentSeverity
      };
      return true;
    }

    return false;
  }

  generateAlert(gameState: GameState): AlertResult | null {
    // isTriggered() already called by engine - removed duplicate check
    const gameId = gameState.gameId;
    const currentWeather = gameState.weatherContext!;
    const current = this.previousWeatherData[gameId];

    // Determine impact level
    const impact = this.determineGameImpact(current.severity, currentWeather);

    const alertKey = `${gameId}_massive_weather_Q${gameState.quarter}_${current.condition}_${current.severity}`;

    const dynamicMessage = this.createDynamicMessage(gameState, current);

    return {
      alertKey,
      type: this.alertType,
      message: `${gameState.awayTeam} @ ${gameState.homeTeam} | ${dynamicMessage}`,
      displayMessage: `🏈 ${dynamicMessage} | Q${gameState.quarter}`,

      context: {
        gameId: gameState.gameId,
        homeTeam: gameState.homeTeam,
        awayTeam: gameState.awayTeam,
        homeScore: gameState.homeScore,
        awayScore: gameState.awayScore,
        quarter: gameState.quarter,
        timeRemaining: gameState.timeRemaining,
        weatherCondition: current.condition,
        weatherSeverity: current.severity,
        gameImpact: impact,
        temperature: (currentWeather as any).temperature,
        situationType: 'MASSIVE_WEATHER'
      },
      priority: this.calculatePriority(current.severity, impact)
    };
  }

  calculateProbability(): number {
    return 85; // High probability for severe weather events
  }

  private calculateWeatherSeverity(condition: string, weatherContext: any): number {
    let severity = 0;

    // Base severity from condition keywords
    for (const severeCondition of this.SEVERE_WEATHER_CONDITIONS) {
      if (condition.includes(severeCondition)) {
        severity += this.getConditionSeverity(severeCondition);
      }
    }

    // Additional factors
    if (condition.includes('heavy')) severity += 2;
    if (condition.includes('severe')) severity += 3;
    if (condition.includes('extreme')) severity += 4;

    // Temperature extremes (for football)
    if ((weatherContext as any).temperature !== undefined) {
      if ((weatherContext as any).temperature <= 20) severity += 2; // Extreme cold
      if ((weatherContext as any).temperature >= 100) severity += 2; // Extreme heat
    }

    // Wind factor (less important but still relevant for extreme conditions)
    if ((weatherContext as any).windSpeed !== undefined && (weatherContext as any).windSpeed >= 30) {
      severity += 2; // Extreme winds
    }

    return Math.min(10, severity); // Cap at 10
  }

  private getConditionSeverity(condition: string): number {
    const severityMap: Record<string, number> = {
      'thunderstorm': 6,
      'lightning': 7,
      'tornado': 10,
      'heavy rain': 4,
      'storm': 5,
      'severe': 6,
      'downpour': 5,
      'deluge': 6,
      'tempest': 7
    };

    return severityMap[condition] || 1;
  }

  private hasPrecipitation(condition: string): boolean {
    const precipitationKeywords = ['rain', 'storm', 'snow', 'sleet', 'drizzle', 'shower'];
    return precipitationKeywords.some(keyword => condition.includes(keyword));
  }

  private determineGameImpact(severity: number, weatherContext: any): 'minimal' | 'moderate' | 'significant' | 'game_delay' | 'cancellation' {
    if (severity >= 9) {
      // Check for cancellation-level conditions
      if (weatherContext.condition?.toLowerCase().includes('tornado') || 
          weatherContext.condition?.toLowerCase().includes('lightning')) {
        return 'cancellation';
      }
      return 'game_delay';
    } else if (severity >= 7) {
      return 'significant';
    } else if (severity >= 5) {
      return 'moderate';
    } else {
      return 'minimal';
    }
  }

  private calculatePriority(severity: number, impact: string): number {
    switch (impact) {
      case 'cancellation': return 95;
      case 'game_delay': return 90;
      case 'significant': return 80;
      case 'moderate': return 70;
      default: return 65;
    }
  }

  private createDynamicMessage(
    gameState: GameState,
    currentWeatherData: any
  ): string {
    const currentWeather = gameState.weatherContext!;
    const condition = currentWeatherData.condition;
    const severity = currentWeatherData.severity;
    const impact = this.determineGameImpact(severity, currentWeather);

    // Base weather description
    let weatherDesc = condition.charAt(0).toUpperCase() + condition.slice(1);

    // Add temperature if extreme
    if ((currentWeather as any).temperature !== undefined) {
      if ((currentWeather as any).temperature <= 20) {
        weatherDesc = `${weatherDesc}, ${(currentWeather as any).temperature}°F`;
      } else if ((currentWeather as any).temperature >= 95) {
        weatherDesc = `${weatherDesc}, ${(currentWeather as any).temperature}°F`;
      }
    }

    // Add wind information if significant
    if ((currentWeather as any).windSpeed !== undefined && (currentWeather as any).windSpeed >= 20) {
      weatherDesc = `${weatherDesc}, ${(currentWeather as any).windSpeed}mph winds`;
    }

    // Create impact description
    let impactDesc = '';
    switch (impact) {
      case 'cancellation':
        impactDesc = 'Game cancellation risk';
        break;
      case 'game_delay':
        impactDesc = 'Game delay likely';
        break;
      case 'significant':
        impactDesc = 'Major game impact';
        break;
      case 'moderate':
        impactDesc = 'Weather impacting game';
        break;
      default:
        impactDesc = 'Weather conditions developing';
    }

    return `${weatherDesc} - ${impactDesc}`;
  }

  private generateWeatherMessage(
    condition: string,
    severity: number,
    impact: string,
    gameState: GameState
  ): string {
    let icon = '⛈️';
    let urgencyText = '';

    switch (impact) {
      case 'cancellation':
        icon = '🚨';
        urgencyText = 'GAME CANCELLATION RISK';
        break;
      case 'game_delay':
        icon = '⚠️';
        urgencyText = 'POTENTIAL GAME DELAY';
        break;
      case 'significant':
        icon = '🌩️';
        urgencyText = 'SEVERE WEATHER IMPACT';
        break;
      case 'moderate':
        icon = '🌧️';
        urgencyText = 'WEATHER CONDITIONS WORSENING';
        break;
      default:
        urgencyText = 'Weather alert';
    }

    // Build comprehensive message
    let message = `${icon} ${gameState.awayTeam} @ ${gameState.homeTeam}: ${urgencyText}`;
    message += ` - ${condition} conditions (severity ${severity}/10)`;

    // Add game context
    if (gameState.quarter && gameState.timeRemaining) {
      message += ` | Q${gameState.quarter} ${gameState.timeRemaining}`;
    } else if (gameState.status === 'scheduled') {
      message += ` | Pre-game conditions`;
    }

    // Add impact description
    switch (impact) {
      case 'cancellation':
        message += ` | Dangerous conditions - game safety at risk`;
        break;
      case 'game_delay':
        message += ` | Officials may delay start/suspend play`;
        break;
      case 'significant':
        message += ` | Affecting gameplay and player safety`;
        break;
      case 'moderate':
        message += ` | Impacting field conditions`;
        break;
    }

    return message;
  }
}

server/services/quality-validator.ts.content:
import { jaccardSimilarity } from './text-utils';

export interface QualityConfig {
  maxPrimaryWords: number;
  maxSecondaryWords: number;
  duplicateThreshold: number;
  nearDuplicateThreshold: number;
}

export interface ValidationResult {
  isValid: boolean;
  reason?: string;
  fallbackToOriginal: boolean;
}

export interface PresentationObject {
  source: 'ai' | 'original';
  title: string;
  body?: string;
  confidence: number;
  tags: string[];
  market?: string;
  bullets: string[];
  duplicateSuppressed: boolean;
}

const QUALITY_CONFIG: QualityConfig = {
  maxPrimaryWords: 14,
  maxSecondaryWords: 18,
  duplicateThreshold: 0.72,
  nearDuplicateThreshold: 0.60
};

function countWords(text: string): number {
  return text.trim().split(/\s+/).length;
}

function isDuplicate(text1: string, text2: string, threshold: number): boolean {
  return jaccardSimilarity(text1, text2) >= threshold;
}

export function validateAIOutput(
  aiTitle: string,
  aiMessage: string,
  originalMessage: string,
  contextualInsights: string[] = []
): ValidationResult {
  const trimmedTitle = aiTitle.trim();
  const trimmedMessage = aiMessage.trim();

  if (!trimmedTitle || trimmedTitle.length === 0) {
    return {
      isValid: false,
      reason: 'empty_primary',
      fallbackToOriginal: true
    };
  }

  if (!trimmedMessage || trimmedMessage.length === 0) {
    return {
      isValid: false,
      reason: 'empty_primary',
      fallbackToOriginal: true
    };
  }

  const titleWords = countWords(trimmedTitle);
  const messageWords = countWords(trimmedMessage);

  if (titleWords < 2) {
    return {
      isValid: false,
      reason: 'too_short',
      fallbackToOriginal: true
    };
  }

  if (messageWords < 2) {
    return {
      isValid: false,
      reason: 'too_short',
      fallbackToOriginal: true
    };
  }

  if (titleWords > QUALITY_CONFIG.maxPrimaryWords) {
    return {
      isValid: false,
      reason: `Title too long: ${titleWords} words (max ${QUALITY_CONFIG.maxPrimaryWords})`,
      fallbackToOriginal: true
    };
  }

  if (messageWords > QUALITY_CONFIG.maxSecondaryWords) {
    return {
      isValid: false,
      reason: `Message too long: ${messageWords} words (max ${QUALITY_CONFIG.maxSecondaryWords})`,
      fallbackToOriginal: true
    };
  }

  const aiContent = `${trimmedTitle} ${trimmedMessage}`.trim();
  if (isDuplicate(aiContent, originalMessage, QUALITY_CONFIG.duplicateThreshold)) {
    return {
      isValid: false,
      reason: `AI output duplicates original (${Math.round(jaccardSimilarity(aiContent, originalMessage) * 100)}% similar)`,
      fallbackToOriginal: true
    };
  }

  return {
    isValid: true,
    fallbackToOriginal: false
  };
}

export function pruneRepetitiveInsights(
  insights: string[],
  referenceText: string
): string[] {
  const pruned: string[] = [];
  const seen = new Set<string>();

  for (const insight of insights) {
    const normalized = insight.toLowerCase().trim();

    if (seen.has(normalized)) {
      continue;
    }

    if (isDuplicate(insight, referenceText, QUALITY_CONFIG.nearDuplicateThreshold)) {
      continue;
    }

    let isDuplicateOfExisting = false;
    for (const existing of pruned) {
      if (isDuplicate(insight, existing, QUALITY_CONFIG.nearDuplicateThreshold)) {
        isDuplicateOfExisting = true;
        break;
      }
    }

    if (!isDuplicateOfExisting) {
      pruned.push(insight);
      seen.add(normalized);
    }
  }

  return pruned;
}

export function resolveDisplay(
  aiEnhancedTitle: string,
  aiEnhancedMessage: string,
  originalMessage: string,
  contextualInsights: string[] = [],
  gamblingBullets: string[] = [],
  confidence: number = 0,
  tags: string[] = [],
  validationResult?: ValidationResult
): PresentationObject {
  let useAI = true;
  let duplicateSuppressed = false;

  if (validationResult && !validationResult.isValid) {
    useAI = false;
  }

  let title = useAI ? aiEnhancedTitle : originalMessage;
  let body = useAI ? aiEnhancedMessage : undefined;

  const titleAndBody = `${title} ${body || ''}`.trim();

  const prunedInsights = pruneRepetitiveInsights(contextualInsights, titleAndBody);

  const deduplicatedBullets: string[] = [];
  const bulletCandidates = [...prunedInsights, ...gamblingBullets];

  for (const bullet of bulletCandidates) {
    if (isDuplicate(bullet, titleAndBody, QUALITY_CONFIG.nearDuplicateThreshold)) {
      duplicateSuppressed = true;
      continue;
    }

    let isDuplicateOfExisting = false;
    for (const existing of deduplicatedBullets) {
      if (isDuplicate(bullet, existing, QUALITY_CONFIG.nearDuplicateThreshold)) {
        isDuplicateOfExisting = true;
        duplicateSuppressed = true;
        break;
      }
    }

    if (!isDuplicateOfExisting && deduplicatedBullets.length < 2) {
      deduplicatedBullets.push(bullet);
    } else if (!isDuplicateOfExisting) {
      duplicateSuppressed = true;
    }
  }

  return {
    source: useAI ? 'ai' : 'original',
    title,
    body,
    confidence,
    tags: tags.slice(0, 3),
    bullets: deduplicatedBullets,
    duplicateSuppressed
  };
}

