    <BaseballDiamond
      runners={enhancedData?.runners || {
        first: false,
        second: false,
        third: false
      }}
      inning={enhancedData?.inning || inning}
      isTopInning={enhancedData?.isTopInning ?? isTopInning}
      outs={enhancedData?.outs || 0}
      balls={enhancedData?.balls || 0}
