                <span className={`ml-2 text-sm font-bold ${trend > 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                  {trend > 0 ? '↗' : '↘'} {Math.abs(trend)}%
                </span>
              )}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

