import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';

type RiskLevel = 'LOW'|'MODERATE'|'ELEVATED'|'HIGH'|'CRITICAL';

export default class TurnoverLikelihoodModule extends BaseAlertModule {
  alertType = 'NFL_TURNOVER_LIKELIHOOD';
  sport = 'NFL';

  // Tunables
  private readonly MIN_RISK_TO_TRIGGER = 34;     // gate to emit
  private readonly HYSTERESIS = 6;               // drop below (34-6) to re-arm
  private readonly MAX_RISK = 75;                // clamp

  // State
  private lastRiskByGame = new Map<string, number>();         // gameId -> last risk

  // Down & distance base table (capped at 10 yards)
  private readonly DOWN_DISTANCE_RISK: Record<number, number[]> = {
    1: [0,2,3,4,5,6,7,8,9,10,12], // index = yardsToGo
    2: [0,4,5,6,7,8,9,11,13,15,18],
    3: [0,8,10,12,15,18,22,26,30,35,40],
    4: [0,15,20,25,30,35,40,45,50,55,60]
  };

  isTriggered(gs: GameState): boolean {
    if (gs.status !== 'live' || !gs.down || !gs.yardsToGo || !gs.fieldPosition) return false;

    // quick prefilter (cheap) – only consider classic turnover-prone moments
    const longThird = gs.down === 3 && (gs.yardsToGo as number) >= 8;
    const fourth = gs.down === 4;
    const deepOwn = (gs.fieldPosition as number) >= 65;             // own 35 or worse
    const endgame = gs.quarter === 4 && this.parseTimeToSeconds(gs.timeRemaining as string) <= 120;

    // Only wake the heavy logic when any of these is true.
    return longThird || fourth || deepOwn || endgame;
  }

  generateAlert(gs: GameState): AlertResult | null {
    // compute once
    const risk = this.calculateTurnoverRisk(gs);
    const last = this.lastRiskByGame.get(gs.gameId) ?? 0;

    // hysteresis gating: only fire on rising edge across threshold
    const armed = last <= (this.MIN_RISK_TO_TRIGGER - this.HYSTERESIS);
    const shouldEmit = risk >= this.MIN_RISK_TO_TRIGGER && (armed || risk > last + 4);

    this.lastRiskByGame.set(gs.gameId, risk);

    if (!shouldEmit) return null;

    const riskLevel = this.getRiskLevel(risk);
    const factors = this.identifyRiskFactors(gs);
    const possessionTeam = this.getPossessionTeam(gs);

    const signature = this.buildSignature(gs); // stable key segments
    const alertKey = `${gs.gameId}:${this.alertType}:${signature}`;

    const message = this.composeMessage(gs, risk, riskLevel, factors[0]);

    return {
      alertKey,
      type: this.alertType,
      message: `${gs.awayTeam} @ ${gs.homeTeam} | ${message}`,
      displayMessage: `🏈 ${message} | Q${gs.quarter}`,
      context: {
        gameId: gs.gameId,
        sport: this.sport,
        homeTeam: gs.homeTeam,
        awayTeam: gs.awayTeam,
        homeScore: gs.homeScore,
        awayScore: gs.awayScore,
        possessionTeam,
        down: gs.down,
        yardsToGo: gs.yardsToGo,
        fieldPosition: gs.fieldPosition,
        quarter: gs.quarter,
        timeRemaining: gs.timeRemaining,
        turnoverRisk: Math.round(risk),
        riskLevel,
        riskFactors: factors,
        primaryRiskFactor: factors[0] || 'Standard Situation',
        situationDescription: this.getSituationDescription(gs),
        alertType: 'PREDICTIVE',
        predictionCategory: 'TURNOVER_RISK',
        nflContext: {
          isFourthDown: gs.down === 4,
          isDeepInOwnTerritory: ((gs.fieldPosition as number) ?? 0) >= 80,
          scoreDifferential: Math.abs((gs.homeScore ?? 0) - (gs.awayScore ?? 0)),
          timePressure: this.classifyTimePressure(gs)
        }
      },
      priority: risk >= 50 ? 95 : risk >= 40 ? 90 : 85
    };
  }

  calculateProbability(gs: GameState): number {
    return this.calculateTurnoverRisk(gs);
  }

  // ---------- Risk model ----------

  private calculateTurnoverRisk(gs: GameState): number {
    if (!gs.down || !gs.yardsToGo || !gs.fieldPosition) return 0;

    // 1) base from down & distance (capped at 10 yards)
    const down = Math.min((gs.down as number), 4);
    const ytg = Math.min(Math.max((gs.yardsToGo as number), 1), 10);
    let score = this.DOWN_DISTANCE_RISK[down]?.[ytg] ?? 5;

    // 2) field position (unified semantics)
    score += this.fieldPositionRisk(gs.fieldPosition as number);

    // 3) situational adders (additive, not multiplicative to avoid blowups)
    score += this.situationAdders(gs);

    // 4) time + score pressure
    score += this.timePressureAdder(gs);
    score += this.desperationAdder(gs);

    // clamp
    return Math.min(Math.max(score, 1), this.MAX_RISK);
  }

  // Own territory is risky (80–99). Opp red zone gets a *small* uptick (traffic).
  private fieldPositionRisk(fpRaw: number): number {
    const fp = Math.min(Math.max(fpRaw, 1), 99);
    if (fp >= 90) return 35;         // own 10
    if (fp >= 80) return 26;         // own 20
    if (fp >= 70) return 22;         // own 30
    if (fp >= 60) return 18;         // own 40
    if (fp >= 50) return 15;         // midfield
    if (fp >= 40) return 12;         // opp 40+
    if (fp >= 21) return 9;          // opp 39–21
    // opp red zone 1–20
    if (fp >= 10) return 11;         // slight congestion uptick
    return 13;                        // goal-to-go congestion
  }

  private situationAdders(gs: GameState): number {
    let add = 0;
    if (gs.down === 4) {
      add += (gs.yardsToGo as number) >= 5 ? 15 : 8;      // 4th-down urgency
    }
    if (gs.down === 3 && (gs.yardsToGo as number) >= 15) add += 8;       // 3rd & very long
    if (gs.down === 3 && (gs.yardsToGo as number) >= 8)  add += 4;       // 3rd & long
    // Goal line stand: defense has leverage on 3rd/4th & <=2 inside the 5
    if (gs.fieldPosition && (gs.fieldPosition as number) <= 5 && (gs.down as number) >= 3 && ((gs.yardsToGo as number) ?? 0) <= 2) {
      add += 6;
    }
    return add;
  }

  private timePressureAdder(gs: GameState): number {
    if (!gs.quarter || !gs.timeRemaining) return 0;
    const t = this.parseTimeToSeconds(gs.timeRemaining as string);
    if (gs.quarter === 4) {
      if (t <= 60) return 12;
      if (t <= 120) return 8;
      if (t <= 300) return 5;
      return 2;
    }
    if (gs.quarter === 2 && t <= 120) return 4; // end of half
    return 0;
    }

  private desperationAdder(gs: GameState): number {
    const h = gs.homeScore ?? 0, a = gs.awayScore ?? 0;
    if (!gs.quarter || !gs.timeRemaining) return 0;
    const t = this.parseTimeToSeconds(gs.timeRemaining as string);
    const diff = Math.abs(h - a);
    if (gs.quarter === 4 && t <= 300) {
      if (diff >= 14) return 10;
      if (diff >= 7)  return 6;
      if (diff >= 3)  return 3;
    }
    if (gs.quarter === 4 && t <= 120 && diff > 0) {
      return diff >= 7 ? 8 : 5; // keep total additive sane
    }
    return 0;
  }

  // ---------- Message + helpers ----------

  private getRiskLevel(r: number): RiskLevel {
    if (r >= 50) return 'CRITICAL';
    if (r >= 40) return 'HIGH';
    if (r >= 30) return 'ELEVATED';
    if (r >= 20) return 'MODERATE';
    return 'LOW';
  }

  private identifyRiskFactors(gs: GameState): string[] {
    const f: string[] = [];
    if (gs.down === 4) f.push('Fourth Down Conversion');
    if (gs.down === 3 && (gs.yardsToGo as number) >= 15) f.push('Very Long Third Down');
    else if (gs.down === 3 && (gs.yardsToGo as number) >= 8) f.push('Long Third Down');
    if (((gs.fieldPosition as number) ?? 0) >= 80) f.push('Deep Own Territory');
    if (((gs.fieldPosition as number) ?? 100) <= 10) f.push('Goal Line Pressure');
    if (gs.quarter === 4) {
      const t = this.parseTimeToSeconds(gs.timeRemaining as string);
      if (t <= 60) f.push('Final Minute');
      else if (t <= 120) f.push('Two-Minute Warning');
    }
    const diff = Math.abs((gs.homeScore ?? 0) - (gs.awayScore ?? 0));
    if (diff >= 7 && gs.quarter === 4) f.push('Desperation Situation');
    return f.length ? f : ['Standard Situation'];
  }

  private composeMessage(gs: GameState, risk: number, level: RiskLevel, primary: string | undefined): string {
    const down = this.getOrdinal((gs.down as number) || 1);
    const ytg = (gs.yardsToGo as number) || 10;
    const fp = (gs.fieldPosition as number) || 50;

    const posDesc =
      fp <= 20 ? `at opponent ${fp}-yard line` :
      fp >= 80 ? `at own ${100 - fp}-yard line` :
                 `at ${fp}-yard line`;

    let tag =
      level === 'CRITICAL' ? 'High turnover risk' :
      level === 'HIGH'     ? 'Elevated turnover risk' :
      level === 'ELEVATED' ? 'Moderate turnover risk' :
      level === 'MODERATE' ? 'Turnover risk' : 'Turnover potential';

    if (primary && primary !== 'Standard Situation') {
      const map: Record<string,string> = {
        'Fourth Down Conversion': 'Critical 4th down risk',
        'Very Long Third Down':   'Very long 3rd down risk',
        'Long Third Down':        'Long 3rd down risk',
        'Deep Own Territory':     'Own territory turnover risk',
        'Goal Line Pressure':     'Goal line traffic risk',
        'Desperation Situation':  'High-pressure turnover risk'
      };
      tag = map[primary] ?? tag;
    }

    return `${down} & ${ytg} ${posDesc} — ${tag} (${Math.round(risk)}%)`;
  }

  private buildSignature(gs: GameState): string {
    // Bucket time to 15s to reduce churn; include down/ytg/field/quarter/possession side
    const t = this.bucketTime(this.parseTimeToSeconds(gs.timeRemaining as string), 15);
    const possStr = gs.possession as string;
    const homeTeamStr = typeof gs.homeTeam === 'string' ? gs.homeTeam : (gs.homeTeam as any).name || '';
    const awayTeamStr = typeof gs.awayTeam === 'string' ? gs.awayTeam : (gs.awayTeam as any).name || '';
    const side = (possStr && (possStr === homeTeamStr || possStr === awayTeamStr)) ? possStr : 'UNK';
    return `Q${gs.quarter}|T${t}|D${gs.down}|Y${Math.min((gs.yardsToGo as number) ?? 0, 10)}|FP${gs.fieldPosition}|P${side}`;
  }

  private getPossessionTeam(gs: GameState): string {
    const possStr = gs.possession as string;
    const homeTeamStr = typeof gs.homeTeam === 'string' ? gs.homeTeam : (gs.homeTeam as any).name || '';
    const awayTeamStr = typeof gs.awayTeam === 'string' ? gs.awayTeam : (gs.awayTeam as any).name || '';
    if (possStr && (possStr === homeTeamStr || possStr === awayTeamStr)) return possStr;
    return 'Possessing Team';
  }

  private getSituationDescription(gs: GameState): string {
    return `${this.getOrdinal((gs.down as number) || 1)} & ${(gs.yardsToGo as number) || 10} at ${(gs.fieldPosition as number) || 50}-yard line`;
  }

  private getOrdinal(n: number): string {
    const ord = ['', '1st','2nd','3rd','4th'];
    return ord[n] || `${n}th`;
  }

  private classifyTimePressure(gs: GameState): 'normal'|'elevated'|'critical' {
    const t = this.parseTimeToSeconds(gs.timeRemaining as string);
    if (gs.quarter === 4 && t <= 60) return 'critical';
    if (gs.quarter === 4 && t <= 300) return 'elevated';
    if (gs.quarter === 2 && t <= 120) return 'elevated';
    return 'normal';
  }

  private parseTimeToSeconds(timeString?: string): number {
    if (!timeString) return 0;
    const clean = timeString.trim().split(/\s+/)[0]; // handles "1:23 4th"
    if (clean.includes(':')) {
      const [m,s] = clean.split(':').map(v => Number.parseInt(v,10) || 0);
      return m*60 + s;
    }
    return Number.parseInt(clean,10) || 0;
  }

  private bucketTime(seconds: number, bucket: number): number {
    return Math.max(0, Math.floor(seconds / bucket) * bucket);
  }
}

import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';


export default class CloseGameModule extends BaseAlertModule {
  alertType = 'NCAAF_CLOSE_GAME';
  sport = 'NCAAF';

  isTriggered(gameState: GameState): boolean {
    console.log(`🔍 NCAAF Close Game check for ${gameState.gameId}: status=${gameState.status}, Q${gameState.quarter}, scores=${gameState.homeScore}-${gameState.awayScore}`);

    // Must be a live game
    if (gameState.status !== 'live') {
      console.log(`❌ Close Game: Game not live (${gameState.status})`);
      return false;
    }

    // Must be in Q3 or Q4 for dramatic close games
    if (gameState.quarter !== 3 && gameState.quarter !== 4) {
      console.log(`❌ Close Game: Not in Q3/Q4 (Q${gameState.quarter})`);
      return false;
    }

    // Check score difference
    const scoreDiff = Math.abs(gameState.homeScore - gameState.awayScore);
    if (scoreDiff > 7) {
      console.log(`❌ Close Game: Score difference too large (${scoreDiff})`);
      return false;
    }

    console.log(`🎯 NCAAF CLOSE GAME TRIGGERED for ${gameState.gameId}: ${scoreDiff} point game in Q${gameState.quarter}`);
    return true;
  }

  generateAlert(gameState: GameState): AlertResult | null {
    const scoreDiff = Math.abs(gameState.homeScore - gameState.awayScore);
    const leadingTeam = gameState.homeScore > gameState.awayScore ? gameState.homeTeam : 
                       gameState.homeScore < gameState.awayScore ? gameState.awayTeam : null;

    return {
      alertKey: `${gameState.gameId}_close_game_q${gameState.quarter}_${Date.now()}`,
      type: this.alertType,
      message: `${gameState.awayTeam} @ ${gameState.homeTeam} | ${this.createDynamicMessage(gameState, scoreDiff, leadingTeam)}`,
      displayMessage: `🏈 ${this.createDynamicMessage(gameState, scoreDiff, leadingTeam)} | Q${gameState.quarter}`,

      context: {
        gameId: gameState.gameId,
        homeTeam: gameState.homeTeam,
        awayTeam: gameState.awayTeam,
        homeScore: gameState.homeScore,
        awayScore: gameState.awayScore,
        quarter: gameState.quarter,
        timeRemaining: gameState.timeRemaining,
        scoreDifference: scoreDiff,
        leadingTeam,
        isTied: scoreDiff === 0
      },
      priority: scoreDiff === 0 ? 95 : 90 - scoreDiff // Higher priority for closer games
    };
  }

  calculateProbability(gameState: GameState): number {
    if (!this.isTriggered(gameState)) return 0;

    const scoreDiff = Math.abs(gameState.homeScore - gameState.awayScore);
    // Higher probability for closer games
    return 100 - (scoreDiff * 10);
  }

  private createDynamicMessage(gameState: GameState, scoreDiff: number, leadingTeam: string | null): string {
    const quarter = gameState.quarter;
    const timeRemaining = gameState.timeRemaining;

    if (scoreDiff === 0) {
      return `Tied game in Q${quarter} - ${timeRemaining} remaining`;
    } else if (scoreDiff <= 3) {
      return `${leadingTeam} leads by ${scoreDiff}, Q${quarter} - ${timeRemaining} left`;
    } else {
      return `${scoreDiff}-point game in Q${quarter} - ${timeRemaining} remaining`;
    }
  }
}

import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';

export default class PitchingChangeModule extends BaseAlertModule {
  alertType = 'MLB_PITCHING_CHANGE';
  sport = 'MLB';

  // Track pitchers per game
  private lastPitchers: Map<string, string> = new Map();

  isTriggered(gameState: GameState): boolean {
    console.log(`🔍 MLB Pitching Change check for ${gameState.gameId}: pitcher=${gameState.currentPitcher}`);

    // Must be a live game
    if (!gameState.isLive) {
      console.log(`❌ Pitching Change: Game not live`);
      return false;
    }

    // Must have current pitcher info
    if (!gameState.currentPitcher) {
      console.log(`❌ Pitching Change: No pitcher info`);
      return false;
    }

    const gameId = gameState.gameId;
    const lastPitcher = this.lastPitchers.get(gameId);

    // First time seeing this game - track but don't trigger
    if (!lastPitcher) {
      this.lastPitchers.set(gameId, gameState.currentPitcher);
      console.log(`📋 Pitching Change: Initial pitcher tracked for ${gameId}: ${gameState.currentPitcher}`);
      return false;
    }

    // Check if pitcher changed
    const pitcherChanged = lastPitcher !== gameState.currentPitcher;

    if (pitcherChanged) {
      console.log(`🎯 MLB PITCHING CHANGE TRIGGERED! Old: ${lastPitcher}, New: ${gameState.currentPitcher}`);
      // Update tracked pitcher
      this.lastPitchers.set(gameId, gameState.currentPitcher);
      return true;
    }

    return false;
  }

  generateAlert(gameState: GameState): AlertResult | null {
    const inningText = gameState.isTopInning ? `Top ${gameState.inning}` : `Bottom ${gameState.inning}`;

    // Build message focusing on betting-critical leverage without duplicate team/score info
    let message = `⚾ PITCHING CHANGE! ${inningText} | New pitcher: ${gameState.currentPitcher}`;

    // Add leverage indicators for betting context
    const leverageIndicators: string[] = [];

    // Determine if this is a high-leverage situation
    const scoreDiff = Math.abs(gameState.homeScore - gameState.awayScore);
    const isCloseGame = scoreDiff <= 3;
    const isLateInning = gameState.inning >= 7;

    if (isLateInning && isCloseGame) {
      leverageIndicators.push('High leverage');
    }

    if (gameState.inning >= 9) {
      leverageIndicators.push('Critical moment');
    }

    // Check for runners in scoring position
    if (gameState.hasSecond || gameState.hasThird) {
      leverageIndicators.push('Runners in scoring position');
    }

    // Add reliever role context if late inning
    if (gameState.inning >= 8) {
      leverageIndicators.push('Setup/closer role');
    }

    if (leverageIndicators.length > 0) {
      message += ` | ${leverageIndicators.join(', ')}`;
    } else {
      message += ` | Standard substitution`;
    }

    const alertResult = {
      alertKey: `${gameState.gameId}_pitching_change_${gameState.inning}_${gameState.isTopInning ? 'top' : 'bot'}`,
      type: this.alertType,
      message: `${gameState.awayTeam} @ ${gameState.homeTeam} | Pitching change`,
      context: {
        gameId: gameState.gameId,
        homeTeam: gameState.homeTeam,
        awayTeam: gameState.awayTeam,
        homeScore: gameState.homeScore,
        awayScore: gameState.awayScore,
        inning: gameState.inning,
        isTopInning: gameState.isTopInning,
        newPitcher: gameState.currentPitcher,
        currentBatter: gameState.currentBatter
      },
      priority: 50
    };

    return alertResult;
  }

  calculateProbability(gameState: GameState): number {
    if (!this.isTriggered(gameState)) return 0;
    return 100; // Certain when pitcher changes
  }
}

import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';

export default class CFLSecondHalfKickoffModule extends BaseAlertModule {
  alertType = 'CFL_SECOND_HALF_KICKOFF';
  sport = 'CFL';

  isTriggered(gameState: GameState): boolean {
    // Second half kickoff - quarter 3 with kickoff time (15:00 or close to it)
    return gameState.status === 'live' && 
           gameState.quarter === 3 && 
           this.isKickoffTime(gameState.timeRemaining);
  }

  generateAlert(gameState: GameState): AlertResult | null {
    // isTriggered() already called by engine - removed duplicate check
    return {
      alertKey: `${gameState.gameId}_cfl_second_half_kickoff`,
      type: this.alertType,
      message: `🏈 SECOND HALF KICKOFF! ${gameState.awayTeam} ${gameState.awayScore}, ${gameState.homeTeam} ${gameState.homeScore} - Second half begins!`,
      context: {
        gameId: gameState.gameId,
        homeTeam: gameState.homeTeam,
        awayTeam: gameState.awayTeam,
        homeScore: gameState.homeScore,
        awayScore: gameState.awayScore,
        quarter: gameState.quarter,
        timeRemaining: gameState.timeRemaining,
        isSecondHalf: true
      },
      priority: 85
    };
  }

  calculateProbability(gameState: GameState): number {
    return this.isTriggered(gameState) ? 100 : 0;
  }

  private isKickoffTime(timeRemaining: string): boolean {
    // Kickoff typically happens at start of quarter (15:00 or close to it)
    if (!timeRemaining) return false;

    try {
      const totalSeconds = this.parseTimeToSeconds(timeRemaining);
      return totalSeconds >= 880 && totalSeconds <= 900; // Between 14:40 and 15:00
    } catch (error) {
      return false;
    }
  }

  private parseTimeToSeconds(timeString: string): number {
    const cleanTime = timeString.trim().split(' ')[0];
    if (cleanTime.includes(':')) {
      const [minutes, seconds] = cleanTime.split(':').map(t => parseInt(t) || 0);
      return (minutes * 60) + seconds;
    }
    return parseInt(cleanTime) || 0;
  }
}

import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';


export default class TwoMinuteWarningModule extends BaseAlertModule {
  alertType = 'NCAAF_TWO_MINUTE_WARNING';
  sport = 'NCAAF';

  isTriggered(gameState: GameState): boolean {
    console.log(`🔍 NCAAF Two Minute check for ${gameState.gameId}: status=${gameState.status}, Q${gameState.quarter}, time=${gameState.timeRemaining}, scores=${gameState.homeScore}-${gameState.awayScore}`);

    // Must be a live game
    if (gameState.status !== 'live') {
      console.log(`❌ Two Minute: Game not live (${gameState.status})`);
      return false;
    }

    // Must be in 2nd or 4th quarter (end of half situations)
    if (gameState.quarter !== 2 && gameState.quarter !== 4) {
      console.log(`❌ Two Minute: Wrong quarter (Q${gameState.quarter})`);
      return false;
    }

    // Trigger in tight window around 2:00 mark (between 1:55 and 2:05)
    const inTwoMinuteWindow = this.isInTwoMinuteWindow(gameState.timeRemaining);
    if (!inTwoMinuteWindow) {
      console.log(`❌ Two Minute: Not in 2:00 window (${gameState.timeRemaining})`);
      return false;
    }

    console.log(`🎯 NCAAF Two Minute WARNING TRIGGERED for ${gameState.gameId}`);
    return true;
  }

  generateAlert(gameState: GameState): AlertResult | null {
    // isTriggered() already called by engine - removed duplicate check
    const isFirstHalf = gameState.quarter === 2;
    const halfText = isFirstHalf ? '1st Half' : '2nd Half';
    const timeSeconds = this.parseTimeToSeconds(gameState.timeRemaining);

    return {
      alertKey: `${gameState.gameId}_two_minute_warning_q${gameState.quarter}_${timeSeconds}`,
      type: this.alertType,
      message: `${gameState.awayTeam} @ ${gameState.homeTeam} | ${this.createDynamicMessage(gameState, halfText)}`,
      displayMessage: `🏈 ${this.createDynamicMessage(gameState, halfText)} | Q${gameState.quarter}`,

      context: {
        gameId: gameState.gameId,
        homeTeam: gameState.homeTeam,
        awayTeam: gameState.awayTeam,
        homeScore: gameState.homeScore,
        awayScore: gameState.awayScore,
        quarter: gameState.quarter,
        timeRemaining: gameState.timeRemaining,
        timeSeconds,
        halfText,
        isFirstHalf,
        twoMinuteWarning: true
      },
      priority: 88
    };
  }

  calculateProbability(gameState: GameState): number {
    if (!this.isTriggered(gameState)) return 0;
    return 95; // High probability since it's exactly at 2:00 mark
  }

  private isInTwoMinuteWindow(timeRemaining: string): boolean {
    if (!timeRemaining) return false;

    try {
      const [minutes, seconds] = timeRemaining.split(':').map(Number);
      const totalSeconds = minutes * 60 + seconds;
      // Tight window: between 1:55 and 2:05 (115-125 seconds)
      return totalSeconds >= 115 && totalSeconds <= 125;
    } catch (error) {
      return false;
    }
  }

  private parseTimeToSeconds(timeString: string): number {
    if (!timeString) return 0;

    try {
      const [minutes, seconds] = timeString.split(':').map(Number);
      return (minutes * 60) + seconds;
    } catch (error) {
      return 0;
    }
  }

  private getScoreDisplay(gameState: GameState): string {
    if (gameState.homeScore === gameState.awayScore) {
      return `Tied ${gameState.homeScore}-${gameState.awayScore}`;
    }

    const leadingTeam = gameState.homeScore > gameState.awayScore ? gameState.homeTeam : gameState.awayTeam;
    const leadingScore = Math.max(gameState.homeScore, gameState.awayScore);
    const trailingScore = Math.min(gameState.homeScore, gameState.awayScore);

    return `${leadingTeam} leads ${leadingScore}-${trailingScore}`;
  }

  private createDynamicMessage(gameState: GameState, halfText: string): string {
    const timeRemaining = gameState.timeRemaining;
    const quarter = gameState.quarter;
    const possession = gameState.possession;
    const scoreDiff = Math.abs(gameState.homeScore - gameState.awayScore);

    // Create contextual two-minute warning message
    if (quarter === 2) {
      // First half - focus on halftime approach
      if (scoreDiff === 0) {
        return `2:00 warning - Tied game approaching halftime`;
      } else if (scoreDiff <= 7) {
        return `2:00 warning - Close game approaching halftime`;
      } else {
        return `2:00 warning - ${halfText} final drive`;
      }
    } else if (quarter === 4) {
      // Fourth quarter - more critical
      if (possession) {
        if (scoreDiff === 0) {
          return `2:00 warning - ${possession} driving, tied game`;
        } else if (scoreDiff <= 3) {
          return `2:00 warning - ${possession} driving, ${scoreDiff}-pt game`;
        } else {
          return `2:00 warning - ${possession} driving in crucial situation`;
        }
      } else {
        if (scoreDiff === 0) {
          return `2:00 warning - Tied game, final two minutes`;
        } else if (scoreDiff <= 7) {
          return `2:00 warning - ${scoreDiff}-pt game, crunch time`;
        } else {
          return `2:00 warning - Critical final two minutes`;
        }
      }
    } else {
      // Fallback
      return `2:00 warning - ${halfText} final two minutes`;
    }
  }
}

import { BaseAlertModule, GameState, AlertResult } from '../../base-engine';


export default class RedZoneModule extends BaseAlertModule {
  alertType = 'NCAAF_RED_ZONE';
  sport = 'NCAAF';

  private lastSignatureByGame: Map<string, string> = new Map();

  isTriggered(gameState: GameState): boolean {
    const gameId = gameState.gameId;

    console.log(`🔍 NCAAF Red Zone check for ${gameState.gameId}: status=${gameState.status}, fieldPos=${gameState.fieldPosition}, quarter=${gameState.quarter}`);

    // Check if we have field position data
    const hasFieldPosition = gameState.fieldPosition !== undefined && gameState.fieldPosition !== null;

    // PATH 1: Normal red zone detection with field position
    if (hasFieldPosition) {
      const meetsBasicConditions = gameState.status === 'live' && 
                                   gameState.fieldPosition <= 20 &&
                                   gameState.fieldPosition > 0;

      // If not in red zone anymore, clear the signature
      if (!meetsBasicConditions || gameState.fieldPosition > 20) {
        this.lastSignatureByGame.delete(gameId);
        console.log(`❌ Red Zone: Not in red zone, clearing signature for ${gameId}`);
        return false;
      }

      // Build current signature
      const currentSignature = this.buildGameSignature(gameState);
      const lastSignature = this.lastSignatureByGame.get(gameId);

      // First time seeing this game in red zone, or signature changed
      if (!lastSignature || lastSignature !== currentSignature) {
        console.log(`🎯 NCAAF Red Zone TRIGGERED for ${gameId}: ${gameState.fieldPosition} yard line (signature changed from "${lastSignature}" to "${currentSignature}")`);
        this.lastSignatureByGame.set(gameId, currentSignature);
        return true;
      }

      // Same signature - don't trigger
      console.log(`⏭️  Red Zone: Same signature, skipping alert for ${gameId}: ${currentSignature}`);
      return false;
    }

    // PATH 2: Q4 close-game fallback when fieldPosition is missing
    const scoreDiff = Math.abs(gameState.homeScore - gameState.awayScore);
    const timeSeconds = this.parseTimeToSeconds(gameState.timeRemaining || '0:00');
    const isQ4Close = gameState.status === 'live' &&
                     gameState.quarter === 4 && 
                     scoreDiff <= 14 && 
                     timeSeconds <= 300; // 5 minutes

    if (isQ4Close) {
      // Build fallback signature
      const currentSignature = this.buildFallbackSignature(gameState);
      const lastSignature = this.lastSignatureByGame.get(gameId);

      if (!lastSignature || lastSignature !== currentSignature) {
        console.log(`🎯 NCAAF Red Zone TRIGGERED (Q4 fallback) for ${gameId}: No field position, Q4 close game (signature changed from "${lastSignature}" to "${currentSignature}")`);
        this.lastSignatureByGame.set(gameId, currentSignature);
        return true;
      }

      console.log(`⏭️  Red Zone Q4 fallback: Same signature, skipping alert for ${gameId}: ${currentSignature}`);
      return false;
    }

    // Neither path triggered - clear signature if exists
    if (this.lastSignatureByGame.has(gameId)) {
      this.lastSignatureByGame.delete(gameId);
      console.log(`❌ Red Zone: Conditions not met, clearing signature for ${gameId}`);
    }
    return false;
  }

  generateAlert(gameState: GameState): AlertResult | null {
    // isTriggered() already called by engine - removed duplicate check
    const probability = this.calculateProbability(gameState);
    const down = gameState.down || 1;
    const yardsToGo = gameState.yardsToGo || 10;

    return {
      alertKey: `${gameState.gameId}_NCAAF_RED_ZONE_${down}_${yardsToGo}`,
      type: this.alertType,
      message: `${gameState.awayTeam} @ ${gameState.homeTeam} | ${this.createDynamicMessage(gameState, down, yardsToGo)}`,
      displayMessage: `🏈 ${this.createDynamicMessage(gameState, down, yardsToGo)} | Q${gameState.quarter}`,
      context: {
        gameId: gameState.gameId,
        sport: gameState.sport,
        homeTeam: gameState.homeTeam,
        awayTeam: gameState.awayTeam,
        homeScore: gameState.homeScore,
        awayScore: gameState.awayScore,
        down: gameState.down,
        yardsToGo: gameState.yardsToGo,
        fieldPosition: gameState.fieldPosition,
        quarter: gameState.quarter,
        timeRemaining: gameState.timeRemaining,
        probability
      },
      priority: probability > 70 ? 90 : 85
    };
  }

  calculateProbability(gameState: GameState): number {
    let probability = 55; // Base red zone probability for college

    // Field position impact
    if (gameState.fieldPosition <= 10) probability += 25; // Goal line area
    else if (gameState.fieldPosition <= 15) probability += 15;

    // Down and distance impact
    if (gameState.down === 1) probability += 20; // College teams more aggressive on 1st down
    else if (gameState.down === 2) probability += 10;
    else if (gameState.down === 3) probability -= 5;
    else if (gameState.down === 4) probability += 15; // College teams go for it more

    // Yards to go impact
    if (gameState.yardsToGo <= 3) probability += 20;
    else if (gameState.yardsToGo <= 7) probability += 10;

    // Time pressure (4th quarter or overtime)
    if (gameState.quarter === 4) probability += 15;
    else if (gameState.quarter >= 5) probability += 20; // Overtime

    // Close game bonus
    const scoreDiff = Math.abs(gameState.homeScore - gameState.awayScore);
    if (scoreDiff <= 7) probability += 10;

    return Math.min(Math.max(probability, 25), 95);
  }

  private getOrdinalSuffix(num: number): string {
    const suffixes = ['th', 'st', 'nd', 'rd'];
    const remainder = num % 100;
    return suffixes[(remainder - 20) % 10] || suffixes[remainder] || suffixes[0];
  }

  private createDynamicMessage(gameState: GameState, down: number, yardsToGo: number): string {
    const fieldPos = gameState.fieldPosition;
    const quarter = gameState.quarter;
    const ordinalSuffix = this.getOrdinalSuffix(down);

    // Create contextual red zone message
    if (fieldPos && fieldPos <= 20) {
      if (yardsToGo <= 3 && fieldPos <= 10) {
        return `${down}${ordinalSuffix} & Goal at ${fieldPos}-yard line`;
      } else if (yardsToGo <= 3) {
        return `${down}${ordinalSuffix} & ${yardsToGo} at ${fieldPos}-yard line`;
      } else {
        return `${down}${ordinalSuffix} & ${yardsToGo} at ${fieldPos}-yard line`;
      }
    } else {
      // Fallback for Q4 close games when field position is missing
      const scoreDiff = Math.abs(gameState.homeScore - gameState.awayScore);
      if (quarter === 4 && scoreDiff <= 7) {
        return `${down}${ordinalSuffix} & ${yardsToGo} - Close Q4 red zone opportunity`;
      } else {
        return `${down}${ordinalSuffix} & ${yardsToGo} - Red zone opportunity`;
      }
    }
  }

  private buildGameSignature(gameState: GameState): string {
    const possessionTeam = this.getPossessionTeam(gameState);
    const quarter = gameState.quarter || 0;
    const down = gameState.down || 0;
    const yardsToGo = gameState.yardsToGo || 0;
    const fieldPosition = gameState.fieldPosition || 0;

    // Field position bucket: group yards into buckets (1-5, 6-10, 11-15, 16-20)
    const fieldPositionBucket = Math.ceil(fieldPosition / 5) * 5;

    // Clock bucket: round time to 30-second intervals to avoid jitter
    const timeSeconds = this.parseTimeToSeconds(gameState.timeRemaining || '0:00');
    const clockBucket = Math.floor(timeSeconds / 30) * 30;

    return `${possessionTeam}|Q${quarter}|${down}&${yardsToGo}|${fieldPositionBucket}|${clockBucket}`;
  }

  private buildFallbackSignature(gameState: GameState): string {
    const possessionTeam = this.getPossessionTeam(gameState);
    const down = gameState.down || 0;
    const yardsToGo = gameState.yardsToGo || 0;

    // Clock bucket: round time to 30-second intervals to avoid jitter
    const timeSeconds = this.parseTimeToSeconds(gameState.timeRemaining || '0:00');
    const clockBucket = Math.floor(timeSeconds / 30) * 30;

    return `${possessionTeam}|Q4_CLOSE|${down}&${yardsToGo}|${clockBucket}`;
  }

  private parseTimeToSeconds(timeString: string): number {
    if (!timeString) return 0;
    const cleanTime = timeString.trim().split(' ')[0];

    if (cleanTime.includes(':')) {
      const [minutes, seconds] = cleanTime.split(':').map(t => parseInt(t) || 0);
      return (minutes * 60) + seconds;
    }

    return parseInt(cleanTime) || 0;
  }

  private getPossessionTeam(gameState: GameState): string {
    // Use possession field if available
    if (gameState.possession) {
      return gameState.possession;
    }

    // Default to away team for simplicity
    return gameState.awayTeam;
  }
}

