  private getFallbackResponse(context: CrossSportContext, startTime: number): UnifiedAIResponse {
    // Smart fallback templates based on alert type and sport
    let enhancedMessage = context.originalMessage || `${context.awayTeam} @ ${context.homeTeam}`;

    // MLB smart templates
    if (context.sport === 'MLB') {
      if (context.alertType.includes('BASES_LOADED')) {
        enhancedMessage = `Bases full, ${context.outs ?? 0} out. RBI spot 🔥`;
      } else if (context.alertType.includes('RISP')) {
        enhancedMessage = `Ducks on the pond: RISP situation with ${context.outs ?? 0} out`;
      } else if (context.alertType.includes('LATE') || context.alertType.includes('PRESSURE')) {
        enhancedMessage = `Late-game pressure: ${context.homeScore}-${context.awayScore}`;
      } else if (context.alertType.includes('WIND')) {
        enhancedMessage = `Wind affecting play: ${context.weather?.windSpeed ?? 15}mph`;
      }
    }

    // NFL/NCAAF/CFL smart templates
    if (['NFL', 'NCAAF', 'CFL'].includes(context.sport)) {
      if (context.alertType.includes('RED_ZONE')) {
        enhancedMessage = `${context.possession || 'Team'} threatening at ${context.fieldPosition ?? 15}-yard line`;
      } else if (context.alertType.includes('FOURTH_DOWN')) {
        enhancedMessage = `4th & ${context.yardsToGo ?? 1}: Go for it or kick? 💰`;
      } else if (context.alertType.includes('TWO_MINUTE')) {
        enhancedMessage = `2-minute warning: ${context.timeRemaining ?? '2:00'} left ⚡`;
      }
    }

    // NBA/WNBA smart templates
    if (['NBA', 'WNBA'].includes(context.sport)) {
      if (context.alertType.includes('CLUTCH') || context.alertType.includes('FINAL')) {
        const scoreDiff = Math.abs(context.homeScore - context.awayScore);
        enhancedMessage = `Crunch time: ${scoreDiff}pt game, ${context.timeLeft ?? 'under 2 min'}`;
      } else if (context.alertType.includes('RUN') || context.alertType.includes('SURGE')) {
        enhancedMessage = `Momentum shift: Team surging 🔥`;
      }
    }

    return {
      sport: context.sport,
      enhancedTitle: `${context.sport} Alert`,
      enhancedMessage,
      contextualInsights: [
        `${context.awayTeam} @ ${context.homeTeam}`,
        `Current: ${context.awayScore}-${context.homeScore}`,
        enhancedMessage
      ].filter(insight => insight && !insight.includes('undefined')),
      actionableRecommendation: enhancedMessage,
      urgencyLevel: context.priority >= 80 ? 'HIGH' as const : 'MEDIUM' as const,
      aiProcessingTime: Date.now() - startTime,
      confidence: Math.min(context.probability || 60, 75),
      sportSpecificData: context
    };
  }

  // === SECURITY METHODS ===

  // 🛡️ SECURITY: Input sanitization to prevent injection attacks
  private sanitizeInput(input: string): string {
    if (!input) return '';

    // Remove potentially dangerous characters and sequences
    return input
      .replace(/<script[^>]*>.*?<\/script>/gi, '') // Remove script tags
      .replace(/<iframe[^>]*>.*?<\/iframe>/gi, '') // Remove iframe tags
      .replace(/javascript:/gi, '') // Remove javascript: protocols
      .replace(/on\w+\s*=/gi, '') // Remove event handlers
      .replace(/[<>"']/g, '') // Remove HTML characters
      .trim()
      .substring(0, 2000); // Limit length
  }

  // 🛡️ SECURITY: AI response sanitization to prevent XSS
  private sanitizeAIResponse(response: string): string {
    if (!response) return '';

    // Sanitize AI response content
    return response
      .replace(/<script[^>]*>.*?<\/script>/gi, '') // Remove script tags
      .replace(/<iframe[^>]*>.*?<\/iframe>/gi, '') // Remove iframe tags  
      .replace(/javascript:/gi, '') // Remove javascript: protocols
      .replace(/on\w+\s*=/gi, '') // Remove event handlers
      .replace(/data:/gi, '') // Remove data: URIs
      .replace(/vbscript:/gi, '') // Remove vbscript: protocols
      .trim()
      .substring(0, 1000); // Limit response length
  }

  // === CIRCUIT BREAKER METHODS ===

  private checkCircuitBreaker(): boolean {
    const now = Date.now();

    // If circuit is open, check if timeout has elapsed
    if (this.circuitBreakerState.isOpen) {
      if (now - this.circuitBreakerState.lastFailureTime > this.circuitBreakerState.resetTimeout) {
        console.log('🔄 Circuit breaker RESET: Attempting recovery');
        this.circuitBreakerState.isOpen = false;
        this.circuitBreakerState.failureCount = 0;
        return true;
      }
      console.warn('⚠️ Circuit breaker OPEN: Skipping AI discovery');
      return false;
    }

    return true;
  }

  private recordSuccess(): void {
    this.circuitBreakerState.failureCount = 0;
  }

  private recordFailure(): void {
    this.circuitBreakerState.failureCount++;
    this.circuitBreakerState.lastFailureTime = Date.now();

    if (this.circuitBreakerState.failureCount >= this.circuitBreakerState.threshold) {
      console.error('❌ Circuit breaker TRIGGERED: Too many AI failures');
      this.circuitBreakerState.isOpen = true;
    }
  }

  getCircuitBreakerStatus(): {
    isOpen: boolean;
    failureCount: number;
    lastFailure: number;
  } {
    return {
      isOpen: this.circuitBreakerState.isOpen,
      failureCount: this.circuitBreakerState.failureCount,
      lastFailure: this.circuitBreakerState.lastFailureTime
    };
  }

  // === AI DISCOVERY METHODS ===

  // Call AI with discovery-specific prompts
  private async callAIDiscovery(context: CrossSportContext): Promise<AIDiscoveryResponse | null> {
    // Check circuit breaker first
    if (!this.checkCircuitBreaker()) {
      return null;  // Circuit open, skip AI call
    }

    const apiKey = process.env.OPENAI_API_KEY;
    if (!apiKey) {
      console.warn('⚠️ AI Discovery: OPENAI_API_KEY not configured');
      return null;
    }

    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), 2800);

    try {
      const prompt = this.buildDiscoveryPrompt(context);
      const body = {
        model: 'gpt-4o',
        messages: [
          { role: 'system', content: this.sanitizeInput(prompt.system).slice(0, 1500) },
          { role: 'user', content: this.sanitizeInput(prompt.user).slice(0, 8000) }
        ],
        max_tokens: 200,
        temperature: 0.3, // Lower temperature for more consistent discovery decisions
        response_format: { type: 'json_object' as const }
      };

      console.log('🔍 AI Discovery: Making OpenAI API call');

      for (let attempt = 0; attempt < 2; attempt++) {
        try {
          const resp = await fetch('https://api.openai.com/v1/chat/completions', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${apiKey}`
            },
            body: JSON.stringify(body),
            signal: controller.signal
          });

          if (resp.ok) {
            const data = await resp.json();
            const text = data.choices?.[0]?.message?.content || '';

            if (!text || text.trim().length === 0) {
              console.warn('⚠️ AI Discovery: Empty response from OpenAI');
              this.recordFailure();  // Increment on null response
              return null;
            }

            // Parse and validate JSON
            const parsed = JSON.parse(text);
            const validated = AIDiscoveryResponseSchema.parse(parsed);

            // Additional validation
            if (!validated.isOpportunity) {
              console.log('🚫 AI Discovery: Not an opportunity - rejecting');
              return null;
            }

            if (!validated.primary || validated.primary.trim().length === 0) {
              console.warn('⚠️ AI discovery returned empty primary message, rejecting');
              this.recordFailure();
              return null;
            }

            if (!validated.confidence || validated.confidence < 50) {
              console.warn('⚠️ AI discovery returned invalid confidence, rejecting');
              this.recordFailure();
              return null;
            }

            console.log(`✅ AI Discovery: Opportunity detected with ${validated.confidence}% confidence`);
            this.recordSuccess();  // Reset failure count on success
            return validated;
          }

          // Retry only on 429/5xx
          if (resp.status === 429 || (resp.status >= 500 && resp.status < 600)) {
            console.warn(`⚠️ OpenAI ${resp.status}, retrying (attempt ${attempt + 1})`);
            await new Promise(r => setTimeout(r, 200 + Math.random() * 250));
            continue;
          }

          console.error('❌ AI Discovery: OpenAI error:', await resp.text());
          this.recordFailure();  // Increment on error
          return null;
        } catch (fetchError: any) {
          if (fetchError?.name === 'AbortError') {
            throw fetchError;
          }
          if (attempt === 1) throw fetchError;
          console.warn(`⚠️ Fetch error, retrying:`, fetchError.message);
          await new Promise(r => setTimeout(r, 200 + Math.random() * 250));
        }
      }
      this.recordFailure();  // Increment if all retries exhausted
      return null;
    } catch (e: any) {
      this.recordFailure();  // Increment on error
      if (e?.name === 'AbortError') {
        console.warn('⌛️ AI Discovery: OpenAI aborted at 2.8s');
      } else {
        console.error('❌ AI Discovery: Error calling OpenAI:', e?.message);
      }
      return null;
    } finally {
      clearTimeout(timer);
    }
  }

